-- Poems batch 299
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('aa19eabf-4efd-4785-b7ae-0c5eb79d0656','竹裏','王安石','宋','宋诗','song-poetry','','[]','竹裏編茅倚石根，竹莖疏處見前村。',32,'全唐诗/poet.song.32000.json','["竹裏編茅倚石根，竹莖疏處見前村。", "閑眠盡日無人到，自有春風爲掃門。"]'),
('4c0fb286-c648-4270-b72b-85a05cd8b2c1','隨意','王安石','宋','宋诗','song-poetry','','[]','隨意柴荆手自開，沿岡度塹復登臺。',32,'全唐诗/poet.song.32000.json','["隨意柴荆手自開，沿岡度塹復登臺。", "小橋風露扁舟月，迷鳥羈雌竟往來。"]'),
('9a89a337-6260-4ccb-a602-0f1a7711576f','秋雲','王安石','宋','宋诗','song-poetry','','[]','秋雲放雨靜山林，萬壑崩湍共一音。',32,'全唐诗/poet.song.32000.json','["秋雲放雨靜山林，萬壑崩湍共一音。", "欲記荒寒無善畫，頼傳悲壯有能琴。"]'),
('c89d4d3d-4010-4779-8927-fb8f30c63238','春風','王安石','宋','宋诗','song-poetry','','[]','春風過柳綠如繰，晴日烝紅出小桃。',32,'全唐诗/poet.song.32000.json','["春風過柳綠如繰，晴日烝紅出小桃。", "池暖水香魚出處，一環清浪湧亭皋。"]'),
('773eee33-64a4-4860-84d1-2b1dac72dc9f','陂麥','王安石','宋','宋诗','song-poetry','','[]','陂麥連雲慘淡黄，綠陰門巷不多凉。',32,'全唐诗/poet.song.32000.json','["陂麥連雲慘淡黄，綠陰門巷不多凉。", "更無一片桃花在，借問春歸有底忙。"]'),
('7e04324c-eccc-45ba-a904-a0e326171823','木末','王安石','宋','宋诗','song-poetry','','[]','木末北山煙冉冉，草根南澗水泠泠。',32,'全唐诗/poet.song.32000.json','["木末北山煙冉冉，草根南澗水泠泠。", "繰成白雪桑重綠，割盡黄雲稻正青。"]'),
('4d493360-f6d6-49f9-b247-d7ef2d342d95','進字說二首','王安石','宋','宋诗','song-poetry','','[]','正名百物自軒轅，野老何知强討論。',64,'全唐诗/poet.song.32000.json','["正名百物自軒轅，野老何知强討論。", "但可與人漫醤瓿，豈能令鬼哭黄昏。", "鼎湖龍去字書存，開闢神機有聖孫。", "湖海老臣無四目，謾將糟粕汙脩門。"]'),
('e1e1e10b-8103-455f-86a6-774845e18539','窺園','王安石','宋','宋诗','song-poetry','','[]','杖策窺園日數巡，攀花弄草興常新。',32,'全唐诗/poet.song.32000.json','["杖策窺園日數巡，攀花弄草興常新。", "董生只被公羊惑，肯信捐書一語真。"]'),
('bd3bda82-ca12-4f39-86a4-0b091142409c','嘲白髮','王安石','宋','宋诗','song-poetry','','[]','久應飄轉作蓬飛，眷惜冠巾未忍違。',32,'全唐诗/poet.song.32000.json','["久應飄轉作蓬飛，眷惜冠巾未忍違。", "種種春風吹不長，星星明月照還稀。"]'),
('966a9aa6-a1b4-4e08-bf67-531ff079c492','代白髮答','王安石','宋','宋诗','song-poetry','','[]','從衰得白自天機，未怪長青與願違。',32,'全唐诗/poet.song.32000.json','["從衰得白自天機，未怪長青與願違。", "看取春條隨日長，會須秋葉向人稀。"]'),
('a7e23e82-c0fe-49d8-957e-215a81b035bb','外厨遺火二首  其一','王安石','宋','宋诗','song-poetry','','[]','竈鬼何爲便赫然，似嫌刀机苦無羶。',32,'全唐诗/poet.song.32000.json','["竈鬼何爲便赫然，似嫌刀机苦無羶。", "圖書得免同煨燼，却頼厨人凊不眠。"]'),
('48422374-dcc0-4382-be68-767db8583c72','外厨遺火二首  其二','王安石','宋','宋诗','song-poetry','','[]','青煙散入夜雲流，赤焰侵尋上瓦溝。',32,'全唐诗/poet.song.32000.json','["青煙散入夜雲流，赤焰侵尋上瓦溝。", "門戶便疑能炙手，比鄰何苦却焦頭。"]'),
('747b9778-5245-4c49-89aa-c567994fff8e','初夏即事','王安石','宋','宋诗','song-poetry','','["\u7530\u56ed", "\u5199\u666f", "\u5199\u98ce", "\u98ce"]','石梁茅屋有彎碕，流水濺濺度兩陂。',32,'全唐诗/poet.song.32000.json','["石梁茅屋有彎碕，流水濺濺度兩陂。", "晴日暖風生麥氣，綠陰幽草勝花時。"]'),
('b973c6d3-709b-49a4-87b2-bffcb360dc75','千蹊','王安石','宋','宋诗','song-poetry','','[]','千蹊百隧散林丘，圖畫風煙一色秋。',32,'全唐诗/poet.song.32000.json','["千蹊百隧散林丘，圖畫風煙一色秋。", "但有興來隨處好，楊朱何苦涕橫流。"]'),
('27caf8ae-8419-4df3-aec7-f91f15911b1d','和陳輔秀才金陵書事','王安石','宋','宋诗','song-poetry','','[]','南郭先生比鷾鴯，年年過我未愆期。',32,'全唐诗/poet.song.32000.json','["南郭先生比鷾鴯，年年過我未愆期。", "休論王謝當時事，大抵烏衣祇舊時。"]'),
('30185dcf-685d-461e-9b12-cb1ac0b2fd01','和耿天騭以竹冠見贈四首  其一','王安石','宋','宋诗','song-poetry','','[]','竹根殊勝竹皮冠，欲著先須短髮乾。',64,'全唐诗/poet.song.32000.json','["竹根殊勝竹皮冠，欲著先須短髮乾。", "要使山林人共見，不持方帽禦風寒。", "無物堪持比此冠，竹皮柔脆穀皮乾。", "故人戀戀綈袍意，豈爲哀憐范叔寒。"]'),
('3fe5c823-1be0-4ab2-82b1-902c91c743a1','和耿天騭以竹冠見贈四首  其二','王安石','宋','宋诗','song-poetry','','[]','玉潤金明信好冠，錯刀剜出蘚紋乾。',32,'全唐诗/poet.song.32000.json','["玉潤金明信好冠，錯刀剜出蘚紋乾。", "不忘君惠常加首，要使歡盟未可寒。"]'),
('9b550dcf-c971-403f-8ec9-7b66ced6ec47','和耿天騭以竹冠見贈四首  其三','王安石','宋','宋诗','song-poetry','','[]','冠工新意斲檀欒，霧卷雲烝久未乾。',32,'全唐诗/poet.song.32000.json','["冠工新意斲檀欒，霧卷雲烝久未乾。", "遺我山林真自稱，何須貂暖配金寒。"]'),
('a9ac7af7-99d9-492e-93ba-b68f1777fced','和郭公甫','王安石','宋','宋诗','song-poetry','','[]','且欲相邀卧看山，扁舟自可送君還。',32,'全唐诗/poet.song.32000.json','["且欲相邀卧看山，扁舟自可送君還。", "留連城郭今如此，知復何時伴我閒。"]'),
('2ccd44c3-bde8-4aac-a9bb-78c0dc25f3cc','葉致遠置洲田以詩言志次其韵二首  其一','王安石','宋','宋诗','song-poetry','','[]','吟嘆君詩久掉頭，知君興不負滄洲。',32,'全唐诗/poet.song.32000.json','["吟嘆君詩久掉頭，知君興不負滄洲。", "土山欲爲羊曇賭，且可專心學奕秋。"]'),
('5906e40b-358d-4576-8843-7587ceb9501b','葉致遠置洲田以詩言志次其韵二首  其二','王安石','宋','宋诗','song-poetry','','[]','若將有限計無涯，自困真同算海沙。',32,'全唐诗/poet.song.32000.json','["若將有限計無涯，自困真同算海沙。", "隨順世緣聊戲劇，莫言河渚是吾家。"]'),
('809f90df-af61-415e-aa1a-44ab4fdb7eb8','又次葉致遠韵二首  其一','王安石','宋','宋诗','song-poetry','','[]','庵成有興亦尋春，風暖荒萊步始勻。',32,'全唐诗/poet.song.32000.json','["庵成有興亦尋春，風暖荒萊步始勻。", "若遇好花須一笑，豈妨迦葉杜多身。"]'),
('e7687f7c-7ad3-4466-a4e7-2de7de648bc6','又次葉致遠韵二首  其二','王安石','宋','宋诗','song-poetry','','[]','明時君尚富春秋，豈比衰翁遠自投。',32,'全唐诗/poet.song.32000.json','["明時君尚富春秋，豈比衰翁遠自投。", "智略未應施畎畝，上前他日望吾丘。"]'),
('7de13b93-b540-4ad8-95f9-53f15e9e1d10','次昌叔韵','王安石','宋','宋诗','song-poetry','','[]','寄公無國寄鍾山，垣屋青松晻靄間。',32,'全唐诗/poet.song.32000.json','["寄公無國寄鍾山，垣屋青松晻靄間。", "長以聲音爲佛事，野風蕭颯水潺湲。"]'),
('83fa37ad-fa4b-4ca3-a4c1-26c432d93a8b','次張唐公韵','王安石','宋','宋诗','song-poetry','','[]','憶昨同追八馬蹄，約公投老此山棲。',32,'全唐诗/poet.song.32000.json','["憶昨同追八馬蹄，約公投老此山棲。", "公乘白鳳今何處，我適新年值白鷄。"]'),
('5d8d5e02-c7bf-4c1b-88ff-099b58a9e90d','次俞秀老韵','王安石','宋','宋诗','song-poetry','','[]','解我葱珩脫孟勞，暮年甘與子同袍。',32,'全唐诗/poet.song.32000.json','["解我葱珩脫孟勞，暮年甘與子同袍。", "新詩比舊增奇峭，若許追攀莫太高。"]'),
('452973c3-cb7d-4735-a8ab-29e1f30e165c','酬宋廷評請序經解','王安石','宋','宋诗','song-poetry','','[]','未曾相識已相憐，香火靈山亦有緣。',32,'全唐诗/poet.song.32000.json','["未曾相識已相憐，香火靈山亦有緣。", "訓釋雖工君尚少，不應急務世人傳。"]'),
('9998edab-174d-482b-a999-501af44cbd05','送耿天騭至渡口','王安石','宋','宋诗','song-poetry','','[]','雪雲江上語依依，不比尋常恨有違。',32,'全唐诗/poet.song.32000.json','["雪雲江上語依依，不比尋常恨有違。", "四十餘年心莫逆，故人如我與君稀。"]'),
('ce0e424e-0aeb-4119-920b-8d017f7e84a3','永慶院送道原還儀真作詩要之','王安石','宋','宋诗','song-poetry','','[]','歲暮青條已見梅，餘花次第相爭開。',32,'全唐诗/poet.song.32000.json','["歲暮青條已見梅，餘花次第相爭開。", "淮南無此山林勝，作意春風更一來。"]'),
('15f0daab-aa7c-4b6d-81ba-8e279c64cf6a','送方劭秘校','王安石','宋','宋诗','song-poetry','','[]','南浦柔條拂地垂，攀翻聊寄我西悲。',32,'全唐诗/poet.song.32000.json','["南浦柔條拂地垂，攀翻聊寄我西悲。", "武昌官柳年年好，他日春風憶此時。"]'),
('7f3f5242-8fd7-4697-8eaf-d07113bcc06b','答韓持國芙蓉堂二首  其一','王安石','宋','宋诗','song-poetry','','[]','投老歸來一幅巾，尚私榮祿備藩臣。',32,'全唐诗/poet.song.32000.json','["投老歸來一幅巾，尚私榮祿備藩臣。", "芙蓉堂下疏秋水，且與龜魚作主人。"]'),
('3cbc480d-a99d-4408-8b05-2585484fe2d9','答韓持國芙蓉堂二首  其二','王安石','宋','宋诗','song-poetry','','[]','乞得膠膠擾擾身，五湖煙水替風塵。',32,'全唐诗/poet.song.32000.json','["乞得膠膠擾擾身，五湖煙水替風塵。", "祇將鳬雁同爲侶，不與龜魚作主人。"]'),
('6f5b5918-97f8-4318-a96d-1ee7eb36819e','長干釋普濟坐化','王安石','宋','宋诗','song-poetry','','[]','投老唯公最故人，相尋長恨隔城闉。',32,'全唐诗/poet.song.32000.json','["投老唯公最故人，相尋長恨隔城闉。", "百年俯仰隨薪盡，畫手空傳浄戒身。"]'),
('637d0acc-14da-458d-a083-5d1619c8a7b9','送黄吉甫入京題清凉寺壁','王安石','宋','宋诗','song-poetry','','[]','薰風洲渚薺花繁，看上征鞍立寺門。',32,'全唐诗/poet.song.32000.json','["薰風洲渚薺花繁，看上征鞍立寺門。", "投老難堪與君別，倚江從此望還轅。"]'),
('9c86b9fa-26ac-44f6-a0b6-44898256e4ed','與道原自何氏宅步至景德寺','王安石','宋','宋诗','song-poetry','','[]','前時偶見花如夢，紅紫紛披競淺深。',32,'全唐诗/poet.song.32000.json','["前時偶見花如夢，紅紫紛披競淺深。", "今日重來如夢覺，靜無餘馥可追尋。"]'),
('991d118a-7a4a-4191-b5d9-c9b561dd843d','過法雲寺','王安石','宋','宋诗','song-poetry','','[]','路過潮溝八九盤，招提雪脊隠雲端。',32,'全唐诗/poet.song.32000.json','["路過潮溝八九盤，招提雪脊隠雲端。", "金鈿一一花總老，翠被重重山更寒。"]'),
('762339f8-436e-4b90-b7b6-a622b93a0d15','光宅寺','王安石','宋','宋诗','song-poetry','','[]','齊安孤起宋興前，光宅相仍一水邊。',32,'全唐诗/poet.song.32000.json','["齊安孤起宋興前，光宅相仍一水邊。", "蜂分蟻爭今不見，故窠遺垤尚依然。"]'),
('afab7660-14e9-48f1-9b41-9f84e1fc877b','題勇老退居院','王安石','宋','宋诗','song-poetry','','[]','道人投老寄山林，偶坐翛然洗我心。',32,'全唐诗/poet.song.32000.json','["道人投老寄山林，偶坐翛然洗我心。", "夢境此身能且在，明年寒食更相尋。"]'),
('9df499fb-8166-4574-a9d3-3aff3f82df5e','與寶覺宿龍華院三絕句  其一','王安石','宋','宋诗','song-poetry','','[]','老於陳迹倦追攀，但見幽人數往還。',32,'全唐诗/poet.song.32000.json','["老於陳迹倦追攀，但見幽人數往還。", "憶我小詩成悵望，鍾山只隔數重山。"]'),
('403674a1-7b61-4347-900d-6767e2b67f32','與寶覺宿龍華院三絕句  其二','王安石','宋','宋诗','song-poetry','','[]','世間投老斷攀緣，忽憶東遊已十年。',32,'全唐诗/poet.song.32000.json','["世間投老斷攀緣，忽憶東遊已十年。", "但有當時京口月，與公隨我故依然。"]'),
('1cb46ebc-bce5-4722-8ed3-82494eb6c178','與寶覺宿龍華院三絕句  其三','王安石','宋','宋诗','song-poetry','','[]','與公京口水雲閒，問月何時照我還。',32,'全唐诗/poet.song.32000.json','["與公京口水雲閒，問月何時照我還。", "邂逅我還還問月，何時照我宿金山。"]'),
('a48a5960-d831-47c6-8beb-7a195b0e9968','清凉寺白雲庵','王安石','宋','宋诗','song-poetry','','[]','庵雲作頂峭無鄰，衣月爲衿靜稱身。',32,'全唐诗/poet.song.32000.json','["庵雲作頂峭無鄰，衣月爲衿靜稱身。", "木落岡巒因自獻，水歸洲渚得橫陳。"]'),
('aa774790-4625-4782-89cb-fc056b1924f5','自定林過西庵','王安石','宋','宋诗','song-poetry','','[]','午雞聲不到禪林，柏子煙中靜擁衾。',32,'全唐诗/poet.song.32000.json','["午雞聲不到禪林，柏子煙中靜擁衾。", "忽憶西巖道人語，杖藜乘興得幽尋。"]'),
('6bff9094-f474-47a8-a681-858fde6a1489','歸庵','王安石','宋','宋诗','song-poetry','','[]','稻畦藏水綠秧齊，松鬣初乾尚有泥。',32,'全唐诗/poet.song.32000.json','["稻畦藏水綠秧齊，松鬣初乾尚有泥。", "縱蹇尋岡歸獨卧，東庵殘夢午時鷄。"]'),
('b98a53c7-9e50-43cb-95be-7fca5959071e','雪中遊北山呈廣州使君和叔同年','王安石','宋','宋诗','song-poetry','','[]','南州歲晚亦花開，有底堪隨驛使來。',32,'全唐诗/poet.song.32000.json','["南州歲晚亦花開，有底堪隨驛使來。", "看取鍾山如許雪，何須持寄嶺頭梅。"]'),
('0c5d5ee9-22ba-45c0-88db-c9b0d02f7bd0','謝安墩二首  其一','王安石','宋','宋诗','song-poetry','','[]','我名公字偶相同，我屋公墩在眼中。',32,'全唐诗/poet.song.32000.json','["我名公字偶相同，我屋公墩在眼中。", "公去我來墩屬我，不應墩姓尚隨公。"]'),
