('1f283ce2-e08f-478a-8bea-92befaf2e896','咏月','王安石','宋','宋诗','song-poetry','','[]','追隨落日盡還生，點綴浮雲暗又明。',32,'全唐诗/poet.song.33000.json','["追隨落日盡還生，點綴浮雲暗又明。", "江有蛟龍山虎豹，清光雖在不堪行。"]'),
('bc581c38-3fc2-4907-af2d-68e1df25b99f','金山','王安石','宋','宋诗','song-poetry','','[]','怪祕陰靈與護持，重丹複碧煥參差。',32,'全唐诗/poet.song.33000.json','["怪祕陰靈與護持，重丹複碧煥參差。", "滄江見底應無日，萬丈孤根世不知。"]'),
('813610f3-7504-41fa-adb9-ddb73f8e696f','疊翠亭','王安石','宋','宋诗','song-poetry','','[]','煙籠遠浦迷芳草，日照澄湖浸碧峰。',32,'全唐诗/poet.song.33000.json','["煙籠遠浦迷芳草，日照澄湖浸碧峰。", "幸有清樽堪酩酊，忍陪良友不從容。"]'),
('d7f45807-2616-46ae-a595-192dbb274fb7','默默','王安石','宋','宋诗','song-poetry','','[]','默默長年有所思，世間談笑强追隨。',32,'全唐诗/poet.song.33000.json','["默默長年有所思，世間談笑强追隨。", "蒼髯欲出朱顔謝，更覺求田問舍遲。"]'),
('2dc68d47-44f8-46a3-85e4-b80374b83bc8','達本','王安石','宋','宋诗','song-poetry','','[]','未能達本且歸根，真照無知豈待言。',32,'全唐诗/poet.song.33000.json','["未能達本且歸根，真照無知豈待言。", "枯木巖前猶失路，那堪春入武陵原。"]'),
('6c87a7f8-b708-41eb-ae72-5cfd4e99113e','寓言二首','王安石','宋','宋诗','song-poetry','','[]','太虛無實可追尋，葉落松枝謾古今。',64,'全唐诗/poet.song.33000.json','["太虛無實可追尋，葉落松枝謾古今。", "若見桃花生聖解，不疑還自有疑心。", "本來無物使人疑，却爲參禪買得癡。", "聞道無情能說法，面牆終日妄尋思。"]'),
('780a1694-179c-4f95-9e24-46e3b187add7','偶書','王安石','宋','宋诗','song-poetry','','[]','穰侯老擅關中事，長恐諸侯客子來。',32,'全唐诗/poet.song.33000.json','["穰侯老擅關中事，長恐諸侯客子來。", "我亦暮年專一壑，每逢車馬便驚猜。"]'),
('f1951bf1-8cdc-444e-b818-0e8139affa68','揚子','王安石','宋','宋诗','song-poetry','','[]','千古雄文造聖真，眇然幽思入無倫。',32,'全唐诗/poet.song.33000.json','["千古雄文造聖真，眇然幽思入無倫。", "他年未免投天祿，虛爲新都著劇秦。"]'),
('d38ddb79-cfe6-4f02-a981-2fe9f518649c','讀維摩經有感','王安石','宋','宋诗','song-poetry','','[]','身如泡沫亦如風，刀割香塗共一空。',32,'全唐诗/poet.song.33000.json','["身如泡沫亦如風，刀割香塗共一空。", "宴坐世間觀此理，維摩雖病有神通。"]'),
('298d7fc2-7e06-43b5-aa78-ee8e7b3156aa','春日即事','王安石','宋','宋诗','song-poetry','','[]','池北池南春水生，桃花深處好閑行。',32,'全唐诗/poet.song.33000.json','["池北池南春水生，桃花深處好閑行。", "細思擾擾夢中事，何用悠悠身後名。"]'),
('c5aebc57-c73b-4cfe-b690-147f09b0fbb1','贈安大師','王安石','宋','宋诗','song-poetry','','[]','獨龍岡北第三峰，逋客歸來老更慵。',32,'全唐诗/poet.song.33000.json','["獨龍岡北第三峰，逋客歸來老更慵。", "敗屋數椽青繚繞，冷雲深處不聞鍾。"]'),
('ddff9657-7f70-4ef0-9596-77772031325a','送李生白華巖修道','王安石','宋','宋诗','song-poetry','','[]','白華巖主是金仙，假作山僧學道禪。',32,'全唐诗/poet.song.33000.json','["白華巖主是金仙，假作山僧學道禪。", "珍重此行吾不及，爲傳消息結因緣。"]'),
('26a80939-f519-4a79-a8a2-7dab1ca3a126','寄道光大師','王安石','宋','宋诗','song-poetry','','[]','秋雨漫漫夜復朝，可嗟蔀屋望重霄。',32,'全唐诗/poet.song.33000.json','["秋雨漫漫夜復朝，可嗟蔀屋望重霄。", "遥知宴坐無餘念，萬事都從劫火燒。"]'),
('2860035e-b4b2-4e0d-9428-781c65a64e97','示報寧長老','王安石','宋','宋诗','song-poetry','','[]','白下亭東鳴一牛，山林陂港浄高秋。',32,'全唐诗/poet.song.33000.json','["白下亭東鳴一牛，山林陂港浄高秋。", "新營棗棫我檀越，曾悟布毛誰比丘。"]'),
('c8c7c185-0b72-41cf-9afe-eaa4a9fa2b1d','紅梨','王安石','宋','宋诗','song-poetry','','[]','紅梨無葉庇花身，黄菊分香委路塵。',32,'全唐诗/poet.song.33000.json','["紅梨無葉庇花身，黄菊分香委路塵。", "歲晚蒼官纔自保，日高青女尚橫陳。"]'),
('e26b299b-b67f-46b7-81a9-b4176b679a59','鴟','王安石','宋','宋诗','song-poetry','','[]','依倚秋風氣象豪，似欺黄雀在蓬蒿。',32,'全唐诗/poet.song.33000.json','["依倚秋風氣象豪，似欺黄雀在蓬蒿。", "不知羽翼青冥上，腐鼠相隨勢亦高。"]'),
('aaa9075e-cd20-4c91-829b-1e49cdd96344','馿二首  其一','王安石','宋','宋诗','song-poetry','','[]','力侔龍象或難堪，脣比仙人亦未慚。',32,'全唐诗/poet.song.33000.json','["力侔龍象或難堪，脣比仙人亦未慚。", "臨路長鳴有真意，盤山弟子久同參。"]'),
('369e4bbe-ac1f-4fdd-bf99-e5ccabad7cbd','馿二首  其二','王安石','宋','宋诗','song-poetry','','[]','雖得康莊亦好還，每逢溝壍便知難。',32,'全唐诗/poet.song.33000.json','["雖得康莊亦好還，每逢溝壍便知難。", "由來此物非他物，莫道何曾似仰山。"]'),
('00cb6b86-ea88-4951-8e29-2de4e4e21947','仁宗皇帝挽辭四首  其一','王安石','宋','宋诗','song-poetry','','[]','去序三朝聖，行崩萬國天。',48,'全唐诗/poet.song.33000.json','["去序三朝聖，行崩萬國天。", "憂勤無曠古，治洽最長年。", "仁育齊高厚，哀思罄幅員。", "欲知千載美，道德冠遺編。"]'),
('f04340c6-165b-43e9-add7-28b1a35a61d5','仁宗皇帝挽辭四首  其二','王安石','宋','宋诗','song-poetry','','[]','憑几微言絕，群臣涕泗揮。',48,'全唐诗/poet.song.33000.json','["憑几微言絕，群臣涕泗揮。", "哀號三級陛，縞素九重圍。", "天上仙遊遠，宮中御座非。", "最悲帷幄侍，不復未明衣。"]'),
('bf1a9b32-e269-4bb6-8988-cbf582f20749','仁宗皇帝挽辭四首  其三','王安石','宋','宋诗','song-poetry','','[]','厭代人間世，收神天上游。',48,'全唐诗/poet.song.33000.json','["厭代人間世，收神天上游。", "遽然虛玉座，不復望珠旒。", "待旦移巾幘，饔人改膳羞。", "尋常飛白几，寂寞暗塵浮。"]'),
('71e9991e-4f7d-4e67-a78a-f6f7d1655011','仁宗皇帝挽辭四首  其四','王安石','宋','宋诗','song-poetry','','[]','同執群方至，因山十月催。',48,'全唐诗/poet.song.33000.json','["同執群方至，因山十月催。", "永違天日表，空有肺肝摧。", "帳殿流蘇卷，鈴歌薤露哀。", "宮中垂曉軔，西去不更回。"]'),
('04715da8-d88e-4554-bf3d-9c28c2386824','英宗皇帝挽辭二首  其一','王安石','宋','宋诗','song-poetry','','[]','御氣方尊極，乘雲已泬寥。',48,'全唐诗/poet.song.33000.json','["御氣方尊極，乘雲已泬寥。", "衣冠萬國會，陵寢百神朝。", "夏鼎傳歸啟，虞羹想見堯。", "誰當授椽筆，論德在瓊瑶。"]'),
('38136cdd-eba7-4e5d-b685-52b613c3f6cf','英宗皇帝挽辭二首  其二','王安石','宋','宋诗','song-poetry','','[]','玉冊上鴻名，猶殘警蹕聲。',48,'全唐诗/poet.song.33000.json','["玉冊上鴻名，猶殘警蹕聲。", "忽辭千歲祝，虛卜五年征。", "羽衛悲哀送，山陵指顧成。", "謳歌歸聖子，世孝在持盈。"]'),
('48d1509a-81af-4a35-9b58-3267c593f784','神宗皇帝挽辭二首  其一','王安石','宋','宋诗','song-poetry','','[]','將聖由天縱，成能與鬼謀。',48,'全唐诗/poet.song.33000.json','["將聖由天縱，成能與鬼謀。", "聰明初四達，俊乂盡旁求。", "一變前無古，三登歲有秋。", "謳歌歸子啟，欽念禹功修。"]'),
('2600776d-6512-43fc-a6f7-1a94d48d1218','神宗皇帝挽辭二首  其二','王安石','宋','宋诗','song-poetry','','[]','城闕宮車轉，山林隧路歸。',48,'全唐诗/poet.song.33000.json','["城闕宮車轉，山林隧路歸。", "蒼梧雲未遠，姑射露先晞。", "玉暗蛟龍蟄，金寒雁鶩飛。", "老臣他日淚，湖海想遺衣。"]'),
('14dfbfc9-4e7a-409f-8bd6-57ae24d309d9','慈聖光獻皇后挽辭二首  其一','王安石','宋','宋诗','song-poetry','','[]','國頼姜任盛，門歸馬鄧高。',48,'全唐诗/poet.song.33000.json','["國頼姜任盛，門歸馬鄧高。", "關雎求窈窕，卷耳念勤勞。", "聖淑才難擬，休明運繼遭。", "岡原今獻卜，帷扆正攀號。"]'),
('c816e6c8-4d95-4714-a799-b004fb79eee5','慈聖光獻皇后挽辭二首  其二','王安石','宋','宋诗','song-poetry','','[]','塗山女德茂，京室母才難。',48,'全唐诗/poet.song.33000.json','["塗山女德茂，京室母才難。", "具美多前志，餘光永後觀。", "遺衣遷館御，祖載出宮菆。", "終始神孫孝，長留萬國歡。"]'),
('05b9bc9e-5788-4f90-b333-a0890a0ab95b','正肅吳公挽辭三首  其一','王安石','宋','宋诗','song-poetry','','[]','從容邊塞議，慷慨廟堂爭。',48,'全唐诗/poet.song.33000.json','["從容邊塞議，慷慨廟堂爭。", "曲突非無驗，方穿有不行。", "搢紳終倚頼，贈襚極哀榮。", "豈慕公孫貴，平生學董生。"]'),
('4753fba8-b6eb-48b1-bf3a-d7de6bbaeeb8','正肅吳公挽辭三首  其二','王安石','宋','宋诗','song-poetry','','[]','應世文章手，宜民政事才。',48,'全唐诗/poet.song.33000.json','["應世文章手，宜民政事才。", "朝多側目忌，士有拊心哀。", "書蠹平生簡，香寒後夜灰。", "悠悠國西路，空得葬車回。"]'),
('ca94c49f-b5a1-4c18-bdbc-cc270ac20942','正肅吳公挽辭三首  其三','王安石','宋','宋诗','song-poetry','','[]','昔繼吳公治，今從子産遊。',48,'全唐诗/poet.song.33000.json','["昔繼吳公治，今從子産遊。", "里門無舊客，鄉國有新丘。", "謀讓禆諶遠，文歸賈誼優。", "此時辜怨寵，西望涕空流。"]'),
('60d5c046-659e-4d04-853c-f83712a34ff1','文元賈公挽辭二首  其一','王安石','宋','宋诗','song-poetry','','[]','功名烜赫在三朝，經術從容輔漢條。',64,'全唐诗/poet.song.33000.json','["功名烜赫在三朝，經術從容輔漢條。", "儒服早紆丞相紱，戎冠再插侍中貂。", "開倉六塔流人復，出甲甘陵叛黨銷。", "東第祇今空畫像，當時於此識風標。"]'),
('5c0e4d5f-64f0-4b19-b37d-7f730ae6e778','文元賈公挽辭二首  其二','王安石','宋','宋诗','song-poetry','','[]','銘旌蕭颯九秋風，薤露悲歌落月中。',64,'全唐诗/poet.song.33000.json','["銘旌蕭颯九秋風，薤露悲歌落月中。", "華屋幾人思謝傅，佳城今日閉滕公。", "名垂竹帛書勳在，神寄丹青審象同。", "天上貂蟬曾夢賜，歸魂應佩紫陽宮。"]'),
('55495b82-0268-4ad5-95c8-31683e828f1a','元獻晏公挽辭三首  其一','王安石','宋','宋诗','song-poetry','','[]','文章晉康樂，經術漢公孫。',48,'全唐诗/poet.song.33000.json','["文章晉康樂，經術漢公孫。", "舊秩疑丞貴，前功保傅尊。", "傳呼猶在耳，會哭已填門。", "蕭瑟城南路，鳴笳上九原。"]'),
('571bb3c7-b081-45cb-a3c1-103f0eef6599','元獻晏公挽辭三首  其二','王安石','宋','宋诗','song-poetry','','[]','終賈年方妙，蕭曹地已親。',48,'全唐诗/poet.song.33000.json','["終賈年方妙，蕭曹地已親。", "優游太平日，密勿老成人。", "抗論辭多秘，賡歌迹已陳。", "功名千載下，不負漢庭臣。"]'),
('a5339cac-13b6-464a-99f8-dfbcc073482a','元獻晏公挽辭三首  其三','王安石','宋','宋诗','song-poetry','','[]','感會真奇遇，飛揚獨妙齡。',48,'全唐诗/poet.song.33000.json','["感會真奇遇，飛揚獨妙齡。", "他年西餞日，此夜上騎星。", "宿惠留藩屏，餘忠在禁庭。", "音容無處所，彷彿寄丹青。"]'),
('3aeca05d-039e-4fd4-a16e-693a138eceba','忠獻韓公挽辭二首  其一','王安石','宋','宋诗','song-poetry','','[]','心期自與衆人殊，骨相知非淺丈夫。',64,'全唐诗/poet.song.33000.json','["心期自與衆人殊，骨相知非淺丈夫。", "獨斡斗杓環帝座，親扶日轂上天衢。", "鋤耰萬里山無盜，衮繡三朝國有儒。", "爽氣忽隨秋露盡，但留陳迹在龜趺。"]'),
('6d0b8b6d-24ec-4fe4-9f03-8253296f7386','忠獻韓公挽辭二首  其二','王安石','宋','宋诗','song-poetry','','[]','兩朝身與國安危，典策哀榮此一時。',64,'全唐诗/poet.song.33000.json','["兩朝身與國安危，典策哀榮此一時。", "木稼嘗聞達官怕，山頹果見哲人萎。", "英姿爽氣歸圖畫，茂德元勳在鼎彝。", "幕府少年今白髮，傷心無路送靈輭。"]'),
('90f690a1-bd59-43e3-9a6b-9707964b5ed1','正憲吳公挽辭','王安石','宋','宋诗','song-poetry','','[]','丙魏雖遭漢道昌，豈如公出值虞唐。',64,'全唐诗/poet.song.33000.json','["丙魏雖遭漢道昌，豈如公出值虞唐。", "秀鍾舊國山川氣，榮附中天日月光。", "更化事功參虎變，贊元時序得金穰。", "傷心鼓吹城南陌，回首新阡柏一行。"]'),
('fd6cfd98-156d-46b6-89fd-de71275198f7','孫威敏公挽辭','王安石','宋','宋诗','song-poetry','','[]','功名一世事，興廢豈人謀。',48,'全唐诗/poet.song.33000.json','["功名一世事，興廢豈人謀。", "重爲蒼生起，終隨逝水流。", "凄凉歸部曲，零落掩山丘。", "許國言猶在，奸諛可使羞。"]'),
('e8122130-d270-4c61-9f6e-c96bf9bbe247','崇禧給事同年馬兄挽辭二首  其一','王安石','宋','宋诗','song-poetry','','[]','慶曆公偕起，元豐我獨傷。',48,'全唐诗/poet.song.33000.json','["慶曆公偕起，元豐我獨傷。", "兩楹終昔夢，五鼎繼前喪。", "薰歇曾攀桂，甘留所憩棠。", "素風知不墜，能世有諸郎。"]'),
('5a3894d3-9000-44f8-be7b-025acbe9f436','崇禧給事同年馬兄挽辭二首  其二','王安石','宋','宋诗','song-poetry','','[]','藏室亡三篋，得之公最多。',48,'全唐诗/poet.song.33000.json','["藏室亡三篋，得之公最多。", "露晞當晚景，川逝作前波。", "惠寄輿人誦，悲傳挽者歌。", "竹西携手處，清淚邈山河。"]'),
('84906c48-9011-4cab-8980-bc2a3280e713','陳動之秘丞挽辭二首  其一','王安石','宋','宋诗','song-poetry','','[]','年高漢賈誼，官過楚荀卿。',48,'全唐诗/poet.song.33000.json','["年高漢賈誼，官過楚荀卿。", "望古君無憾，論今我未平。", "有風吹畫翣，無日照佳城。", "空復文章在，流傳世上名。"]'),
('4ec42636-96b2-41ae-a296-e94f3a354831','陳動之秘丞挽辭二首  其二','王安石','宋','宋诗','song-poetry','','[]','人間三十六，追逐孔鸞飛。',48,'全唐诗/poet.song.33000.json','["人間三十六，追逐孔鸞飛。", "似欲來爲瑞，如何去不歸。", "琴樽已寂寞，筆墨尚光輝。", "空復平生友，西華豈易依。"]'),
('97c66de7-1d99-44fb-8c20-78461e4eff0e','贈工部侍郎鄭公挽辭','王安石','宋','宋诗','song-poetry','','[]','地蟠江漢久知靈，通德門中見老成。',64,'全唐诗/poet.song.33000.json','["地蟠江漢久知靈，通德門中見老成。", "南去伏波推將略，北來光祿擅詩名。", "密章贈襚連三組，畫翣喪車載一旌。", "陰德故應多後福，可能生子但升卿。"]'),
('00f29e17-cf76-4707-b3de-bcff57b896a2','致仕虞部曲江譚君挽辭','王安石','宋','宋诗','song-poetry','','[]','同時獻賦久無人，握手悲歡迹已陳。',64,'全唐诗/poet.song.33000.json','["同時獻賦久無人，握手悲歡迹已陳。", "它日白衣霄漢志，暮年朱紱水雲身。", "虛容劍几今長夜，小隠山林祇舊春。", "豈惜埋辭追往事，齒衰才盡獨傷神。"]'),
('8c1b3e55-bc32-4156-8682-7fce6769ed21','馬玘大夫挽辭','王安石','宋','宋诗','song-poetry','','[]','冠蓋青門道，知君自少時。',48,'全唐诗/poet.song.33000.json','["冠蓋青門道，知君自少時。", "從容他日喜，奄忽暮年悲。", "江月明丹旐，湖風冷繐帷。", "音容雖可想，材力竟何施。"]'),
('0f40ecee-ed19-427d-837d-d84acf267b5e','宋中道挽辭','王安石','宋','宋诗','song-poetry','','[]','文史傳家學，聲名動帝除。',48,'全唐诗/poet.song.33000.json','["文史傳家學，聲名動帝除。", "蘭堂空作賦，金匱不讎書。", "勝事悲疇昔，清談想緒餘。", "吹簫索上去，歸國有魂車。"]'),
('64fa521e-5f5f-4784-bcf1-436cb0d99426','王中甫學士挽辭','王安石','宋','宋诗','song-poetry','','[]','同學金陵最少年，奏書曾用牘三千。',64,'全唐诗/poet.song.33000.json','["同學金陵最少年，奏書曾用牘三千。", "盛名非復居人後，壯歲如何棄我先。", "種橘園林無舊業，採蘋洲渚有新篇。", "蒜山東路春風綠，埋沒誰知太守阡。"]'),
('9bb3c0f9-103d-411a-943f-21676450dc90','王逢原挽辭','王安石','宋','宋诗','song-poetry','','[]','蒿里竟何在，死生從此分。',48,'全唐诗/poet.song.33000.json','["蒿里竟何在，死生從此分。", "謾傳仙掌籍，誰見鬼修文。", "蔡琰能傳業，侯芭爲起墳。", "傷心北風路，吹淚濕江雲。"]'),
('ba648621-f30f-4c8d-8659-99fb4f0891f0','葛興祖挽辭','王安石','宋','宋诗','song-poetry','','[]','憶隨諸彥附青雲，場屋聲名看出群。',64,'全唐诗/poet.song.33000.json','["憶隨諸彥附青雲，場屋聲名看出群。", "孫寶暮年猶主簿，卜商今日更修文。", "山川凜凜平生氣，草木蕭蕭數尺墳。", "欲寫此哀終不盡，但令千載少知君。"]'),
('f654fbd7-22c2-4b70-9f88-0c7e5c73406e','河中使君修撰陸公挽辭三首  其一','王安石','宋','宋诗','song-poetry','','[]','文采機雲後，知名實妙年。',48,'全唐诗/poet.song.33000.json','["文采機雲後，知名實妙年。", "銀鉤工壯麗，金薤富清妍。", "批鳳多新貴，憑熊數外遷。", "空令猗氏監，遺愛有良田。"]'),
('93f94ebf-f3b9-416f-ace2-cf3979960581','河中使君修撰陸公挽辭三首  其二','王安石','宋','宋诗','song-poetry','','[]','皖城初得故人詩，嘆息龍媒踠壯時。',64,'全唐诗/poet.song.33000.json','["皖城初得故人詩，嘆息龍媒踠壯時。", "太史滯留終不偶，中郎制作遂無施。", "二千石祿今何有，四十車書昔漫知。", "海曲冷雲埋拱木，延州空掛暮年悲。"]'),
('2b6f4e97-fffd-4095-b0f2-2e27ff144bcb','河中使君修撰陸公挽辭三首  其三','王安石','宋','宋诗','song-poetry','','[]','前旌一幅粉書名，行路知君亦涕零。',64,'全唐诗/poet.song.33000.json','["前旌一幅粉書名，行路知君亦涕零。", "遂失詞人空甫里，謾留悲鶴老華亭。", "主張壽祿無三甲，收拾文章有六丁。", "歸處仙龕終不遠，新墳東見海山青。"]'),
('0d91269d-4a61-4cef-b2c1-fa849e5fef44','王子直挽辭','王安石','宋','宋诗','song-poetry','','[]','多才自合至公卿，豈料青衫困一生。',64,'全唐诗/poet.song.33000.json','["多才自合至公卿，豈料青衫困一生。", "太史有書能敘事，子雲於世不徼名。", "丘墳慘淡箕山綠，門巷蕭條潁水清。", "握手笑言如昨日，白頭東望一傷情。"]'),
('ca39674a-9d62-4089-868e-11a4aaf69e05','孫君挽辭','王安石','宋','宋诗','song-poetry','','[]','喪車上新壟，哀挽轉空山。',48,'全唐诗/poet.song.33000.json','["喪車上新壟，哀挽轉空山。", "名與碑長在，魂隨帛暫還。", "無兒漫黄卷，有母亦朱顔。", "俛仰平生事，相看一夢間。"]'),
('86833d34-ea59-489f-afaa-f17ae3690434','處士葛君挽辭','王安石','宋','宋诗','song-poetry','','[]','楚人黄歇地，晉代葛洪家。',48,'全唐诗/poet.song.33000.json','["楚人黄歇地，晉代葛洪家。", "特擅山川秀，相承黻冕華。", "猗君有清尚，於世不雄夸。", "令子能傳業，流光未可涯。"]'),
('6dc5eccd-3e50-4341-a5a6-659ebe7f762d','永壽縣太君周氏挽辭二首  其一','王安石','宋','宋诗','song-poetry','','[]','永壽開新邑，長沙返舊塋。',48,'全唐诗/poet.song.33000.json','["永壽開新邑，長沙返舊塋。", "金葩冷鈿軸，粉字暗銘旌。", "薤久露難濕，蘭餘風尚清。", "慶鍾知有在，令子合升卿。"]'),
('513c4495-8794-41e2-aa10-23da6f032bf3','永壽縣太君周氏挽辭二首  其二','王安石','宋','宋诗','song-poetry','','[]','子引金閨籍，身開石窌封。',48,'全唐诗/poet.song.33000.json','["子引金閨籍，身開石窌封。", "靈輴悲吉路，象服儼虛容。", "楚挽雖多相，萊衣不更縫。", "誰知逝川底，劍自喜相逢。"]'),
('7710cd6d-dd3a-42fe-b61f-1fce3668858b','致仕邵少卿挽辭二首  其一','王安石','宋','宋诗','song-poetry','','[]','謝朓城中守，梁鴻墓下歸。',48,'全唐诗/poet.song.33000.json','["謝朓城中守，梁鴻墓下歸。", "素車馳吉路，丹旐卷寒輝。", "撫几虛容在，瞻圖實貌非。", "無因置一酹，空此嘆長違。"]'),
('ccf522e4-c8e1-4a60-aaab-34cbb894f840','致仕邵少卿挽辭二首  其二','王安石','宋','宋诗','song-poetry','','[]','杯酒邗溝上，紛紛已十年。',48,'全唐诗/poet.song.33000.json','["杯酒邗溝上，紛紛已十年。", "音容常想見，風迹每流傳。", "老去元卿位，新開太守阡。", "慶門當更大，子弟固多賢。"]'),
('fa6e99ca-ba2e-4dcf-9245-5c59f83d17a7','葛郎中挽辭二首  其一','王安石','宋','宋诗','song-poetry','','[]','卷卷繐帷輕，空堂晝哭聲。',48,'全唐诗/poet.song.33000.json','["卷卷繐帷輕，空堂晝哭聲。", "衣冠遺故物，杯案若平生。", "白馬有悲送，赤車非古行。", "低徊九原日，光景在銘旌。"]'),
('4738da3d-8b83-42fc-9284-72732a3e57e9','葛郎中挽辭二首  其二','王安石','宋','宋诗','song-poetry','','[]','蠻荆長往地，湖海獨歸時。',48,'全唐诗/poet.song.33000.json','["蠻荆長往地，湖海獨歸時。", "旅櫬蛟龍護，銘旌雁鶩隨。", "此生要有盡，何物告無期。", "一片幽堂石，公知我不欺。"]'),
('e364c936-532c-41d1-8f02-94f82863a1fe','悼王致處士','王安石','宋','宋诗','song-poetry','','[]','處士生涯水一瓢，行年七十更蕭條。',64,'全唐诗/poet.song.33000.json','["處士生涯水一瓢，行年七十更蕭條。", "老妻稻下分遺秉，弱子松間拾墮樵。", "豈有聲名高後世，遂無饘粥永今朝。", "窮魂散漫知何處，甬水東西不可招。"]'),
('a6db260d-167f-4006-8780-bd02ecb66e56','蘇才翁挽辭二首  其一','王安石','宋','宋诗','song-poetry','','[]','空餘一丹旐，無復兩朱轓。',48,'全唐诗/poet.song.33000.json','["空餘一丹旐，無復兩朱轓。", "寂寞蒜山渡，陂陀京口原。", "音容歸繪畫，才業付兒孫。", "尚有故人淚，滄江相與翻。"]'),
('26bdccde-efbc-451a-92cd-c4edb3bf97f0','蘇才翁挽辭二首  其二','王安石','宋','宋诗','song-poetry','','[]','翰墨隨談嘯，風流在弟兄。',48,'全唐诗/poet.song.33000.json','["翰墨隨談嘯，風流在弟兄。", "浮名同逆旅，壯志負平生。", "使節何年去，喪車故老迎。", "悠悠京口外，落日照銘旌。"]'),
('01ddd946-54dd-46a6-a42c-c6cd15877633','悼慧休','王安石','宋','宋诗','song-poetry','','[]','休公遂不起，難料復難忘。',24,'全唐诗/poet.song.33000.json','["休公遂不起，難料復難忘。", "玉骨隨薪盡，空留一分香。"]'),
('cd34e492-c43e-4a1c-b8d7-0c2f3cd28855','送吳顯道五首  其一','王安石','宋','宋诗','song-poetry','','[]','五湖大浪如銀山，問君西遊何當還。',130,'全唐诗/poet.song.33000.json','["五湖大浪如銀山，問君西遊何當還。", "以手撫膺坐長嘆，空手無金行路難。", "丈夫意有在，吾徒且加餐。", "屏風九疊雲錦張，千峰如連環。", "上有橫河斷海之浮雲，可望不可攀。", "飛空結樓臺，動影裊窕沖融間。", "沛然乘天遊，下看塵世悲人寰。", "泊舟潯陽郭，去去翔寥廓。", "君今幸未成老翁，衰老不復如今樂。"]'),
('8cc824a5-9091-424f-89af-d47c029cc5b0','送吳顯道五首  其二','王安石','宋','宋诗','song-poetry','','[]','滕王高閣臨江渚，東邊日出西邊雨。',188,'全唐诗/poet.song.33000.json','["滕王高閣臨江渚，東邊日出西邊雨。", "十五年前此會同，天際張帷列樽俎。", "公今此去何時歸，我今停杯一問之。", "春風兩岸水楊柳，昔日青青今在否。", "偶向東湖更向東，杏花兩株能白紅。", "落拓舊遊應記得，插花走馬月明中。", "荏苒荏苒瞻西海，明年花開復誰在。", "杏花楊柳年年好，南去北來人自老。", "少壯幾時奈老何，與君把箸擊盤歌。", "歌罷仰天嘆，六龍忽蹉跎。", "眼中了了見鄉國，自是不歸歸便得。", "欲往城南望城北，此心炯炯君應識。"]'),
('2e633ad7-5ffb-4646-9d61-c99314ac8b9f','送吳顯道五首  其三','王安石','宋','宋诗','song-poetry','','[]','臨川樓上柅園中，羅幃繡幕圍香風。',64,'全唐诗/poet.song.33000.json','["臨川樓上柅園中，羅幃繡幕圍香風。", "觥船一棹百分空，看朱成碧顔始紅。", "杏花楊柳年年好，南去北來人自老。", "舊事無人可共論，惟君與我同懷抱。"]'),
('ebc68fde-f003-4803-af9f-90f4a4eeab4b','送吳顯道五首  其四','王安石','宋','宋诗','song-poetry','','[]','忽憶舊鄉頭已白，牙齒欲落真可惜。',32,'全唐诗/poet.song.33000.json','["忽憶舊鄉頭已白，牙齒欲落真可惜。", "臨江把臂難再得，江水江花豈終極。"]'),
('4db22b4b-acac-4f58-9ced-cf2231d21968','送吳顯道五首  其五','王安石','宋','宋诗','song-poetry','','[]','百年多病獨登臺，知有歸日眉放開。',32,'全唐诗/poet.song.33000.json','["百年多病獨登臺，知有歸日眉放開。", "功名富貴何足道，且賦淵明歸去來。"]'),
('d7783f31-02e3-4922-a6ac-6fb44a642ad4','送吳顯道南歸','王安石','宋','宋诗','song-poetry','','[]','君不見蔡澤栖遲世看醜，豪氣英風亦何有。',191,'全唐诗/poet.song.33000.json','["君不見蔡澤栖遲世看醜，豪氣英風亦何有。", "忽然變軒昂，盛事傳不朽。", "君今幸未成老翁，二十八宿羅心胸。", "何不上書自薦達，封侯起第一日中。", "秋月春風等閑度，山中舊宅無人住。", "宅中青桑葉宛宛，澗水流過田中路。", "遥知楊柳是門處，萬里蒼蒼煙水暮。", "我欲尋之不憚遠，君又暫來還徑去。", "紅亭驛路掛城頭，憶君祇欲苦死留。", "天際張帷列樽俎，君歌聲酸辭且苦。", "人生憔悴生理難，使人聽此凋朱顔。", "勸君更盡一杯酒，明日路長山復山。"]'),
('04c016a1-32ba-497a-9e6e-6ed5358df678','送劉貢甫謫官衡陽','王安石','宋','宋诗','song-poetry','','[]','劉郎劉郎莫先起，遇酒當歌且歡喜。',102,'全唐诗/poet.song.33000.json','["劉郎劉郎莫先起，遇酒當歌且歡喜。", "船頭朝轉暮千里，眼中之人吾老矣。", "九疑聯綿皆相似，負雪崔嵬插花裏。", "萬里衡陽雁，尋常到此迴。", "行逢二三月，好與雁同來。", "雁來人不來，如何不飲令心哀。", "莫厭瀟湘少人處，謫官樽俎定常開。"]'),
('b9653e98-05dd-448b-973a-193635b9cc3d','贈寶覺','王安石','宋','宋诗','song-poetry','','[]','大師京國舊，興趣江湖迥。',96,'全唐诗/poet.song.33000.json','["大師京國舊，興趣江湖迥。", "往與惠詢輩，一宿金山頂。", "懷哉苦留戀，王事有朝請。", "別來能幾時，浮念劇含梗。", "今朝忽相見，眸子清炯炯。", "夜闌接軟語，令人發深省。", "化城出天半，遠色有諸嶺。", "白首對汀洲，猶思理煙艇。"]'),
('8257ce9f-4a93-4a4c-9c12-f65e75349063','金山寺','王安石','宋','宋诗','song-poetry','','[]','招提憑高岡，四面斷行旅。',240,'全唐诗/poet.song.33000.json','["招提憑高岡，四面斷行旅。", "勝地猶在險，浮梁裊相拄。", "大江當我前，颭灧翠綃舞。", "通流與厨會，甘美勝牛乳。", "扣欄出黿鼉，幽姿可時睹。", "夜深殿突兀，太微凝帝宇。", "壁立兩崖對，迢迢隔雲雨。", "天多剩得月，月落聞津鼓。", "夜風一何喧，大舶夾雙艣。", "顛沉在須臾，我自檝迎汝。", "始知像教力，但度無所苦。", "憶昨狼狽初，只見石與土。", "榮華一朝盡，土梗空俯僂。", "人事隨轉燭，蒼茫竟誰主。", "咄嗟檀施開，繡楹盤萬礎。", "高閣切星辰，新秋照牛女。", "湯休起我病，轉上青天去。", "攝身凌蒼霞，同憑朱欄語。", "我歌爾其聆，幽憤得一吐。", "誰言張處士，雄筆映千古。"]'),
('af98167b-4790-4122-8120-818a7099a68f','化城閣','王安石','宋','宋诗','song-poetry','','[]','曾宮憑風回，兩岸聞鍾聲。',156,'全唐诗/poet.song.33000.json','["曾宮憑風回，兩岸聞鍾聲。", "百里見秋毫，搆雲有高營。", "化城若化出，仰攀日月行。", "俛視大江奔，衆山遥相迎。", "大江蟠㠌根，旋流自成浪。", "却略羅翠屏，秀色各異狀。", "楞伽海中山，迥出霄漢上。", "中有不死庭，天龍盡回向。", "惜哉不得往，側坐渺難望。", "擁掩難恕宥，意欲鏟疊嶂。", "登臨獨無語，一望一怊悵。", "忽憶少年時，孤嶼坐題詩。", "空懷焉能果，唯有故人知。"]'),
('a99a6b1b-700a-4780-b245-d8e67c6d1891','明妃曲','王安石','宋','宋诗','song-poetry','','[]','我本漢家子，早入深宮裏。',116,'全唐诗/poet.song.33000.json','["我本漢家子，早入深宮裏。", "遠嫁單于國，憔悴無復理。", "穹廬爲室旃爲牆，胡塵暗天道路長。", "去住彼此無消息，明明漢月空相識。", "死生難有却回身，不忍回看舊寫真。", "玉顔不是黄金少，愛把丹青錯畫人。", "朝爲漢宮妃，暮作胡地妾。", "獨留青塚向黄昏，顔色如花命如葉。"]'),
('c85e3469-d793-4362-9093-3bccb5b95ddb','懷元度四首  其一','王安石','宋','宋诗','song-poetry','','[]','秋水纔深四五尺，扁舟斗轉疾於飛。',32,'全唐诗/poet.song.33000.json','["秋水纔深四五尺，扁舟斗轉疾於飛。", "可憐物色阻携手，正是歸時君不歸。"]'),
('7fbec9b8-24c4-4cea-8c6d-8db7d3518919','懷元度四首  其二','王安石','宋','宋诗','song-poetry','','[]','舍南舍北皆春水，恰似蒲萄初醱醅。',32,'全唐诗/poet.song.33000.json','["舍南舍北皆春水，恰似蒲萄初醱醅。", "不見秘書心若失，百年多病獨登臺。"]'),
('34d88a67-a92e-46c3-bfa4-7a7aed3de35e','懷元度四首  其三','王安石','宋','宋诗','song-poetry','','[]','思君携手安能得，上盡重城更上樓。',32,'全唐诗/poet.song.33000.json','["思君携手安能得，上盡重城更上樓。", "時獨看雲淚橫臆，長安不見使人愁。"]'),
('cabf20fe-3e05-4057-be52-698a3940d089','懷元度四首  其四','王安石','宋','宋诗','song-poetry','','[]','自君之出矣，何其挂懷抱。',48,'全唐诗/poet.song.33000.json','["自君之出矣，何其挂懷抱。", "孤坐屢窮辰，山林迹如掃。", "數枝石榴發，豈無一時好。", "不可持寄君，思君令人老。"]'),
('7feef873-c7a2-4092-96fb-f0cd47573ebb','招元度','王安石','宋','宋诗','song-poetry','','[]','早知皆是自拘囚，年少因何有旅愁。',32,'全唐诗/poet.song.33000.json','["早知皆是自拘囚，年少因何有旅愁。", "自是不歸歸便得，陸乘肩輿水乘舟。"]'),
('dc923251-fb2a-4029-a619-441a1b128f0d','示黄吉甫','王安石','宋','宋诗','song-poetry','','[]','三山半落青天外，勢比凌歊宋武臺。',32,'全唐诗/poet.song.33000.json','["三山半落青天外，勢比凌歊宋武臺。", "塵世難逢開口笑，生前相遇且銜杯。"]'),
('4beca275-df43-43b4-b07f-bb55fcff83db','送張明甫','王安石','宋','宋诗','song-poetry','','[]','觥船一棹百分空，十五年前此會同。',32,'全唐诗/poet.song.33000.json','["觥船一棹百分空，十五年前此會同。", "南去北來人自老，桃花依舊笑春風。"]'),
('bde43088-2849-4de9-9752-f37ccb30f8fe','贈張軒民贊善','王安石','宋','宋诗','song-poetry','','[]','潮打空城寂寞迴，百年多病獨登臺。',32,'全唐诗/poet.song.33000.json','["潮打空城寂寞迴，百年多病獨登臺。", "誰人得似張公子，有底忙時不肯來。"]'),
('d36fea4b-1cfe-45c4-bf17-8f1eb45ec07a','望之將行','王安石','宋','宋诗','song-poetry','','[]','江涵秋景雁初飛，沙尾長檣發漸稀。',32,'全唐诗/poet.song.33000.json','["江涵秋景雁初飛，沙尾長檣發漸稀。", "惆悵無因見范蠡，夕陽長送釣船歸。"]'),
('7b55fdcf-6314-4aa6-91e7-0d4f030165b3','招葉致遠','王安石','宋','宋诗','song-poetry','','[]','山桃野杏兩三栽，嫩葉商量細細開。',32,'全唐诗/poet.song.33000.json','["山桃野杏兩三栽，嫩葉商量細細開。", "最是一年春好處，明朝有意抱琴來。"]'),
('126c0aa1-18d7-402c-999d-fe2c2d0dc397','獨行','王安石','宋','宋诗','song-poetry','','[]','朱顔日夜不如故，深感杏花相映紅。',32,'全唐诗/poet.song.33000.json','["朱顔日夜不如故，深感杏花相映紅。", "盡日獨行春色裏，醉吟誰肯伴衰翁。"]'),
('73e6dbac-96f9-4183-af5a-2495bf646604','江口','王安石','宋','宋诗','song-poetry','','[]','六朝文物草連空，今古無端入望中。',32,'全唐诗/poet.song.33000.json','["六朝文物草連空，今古無端入望中。", "江上晚來堪畫處，參差煙樹五湖東。"]'),
('45e7a53b-3551-478a-adfb-b5b9d687a7b1','戲贈湛源','王安石','宋','宋诗','song-poetry','','[]','恰有三百青銅錢，憑君爲算小行年。',32,'全唐诗/poet.song.33000.json','["恰有三百青銅錢，憑君爲算小行年。", "坐中亦有江南客，自斷此生休問天。"]'),
('759daa31-d82b-4b35-ada2-79d2b1143656','與北山道人','王安石','宋','宋诗','song-poetry','','[]','可惜昂藏一丈夫，生來不讀半行書。',32,'全唐诗/poet.song.33000.json','["可惜昂藏一丈夫，生來不讀半行書。", "子雲識字終投閣，幸是元無免破除。"]'),
('7449d3d2-4af4-4e8f-90a9-7778e09c2ce3','梅花','王安石','宋','宋诗','song-poetry','','[]','白玉堂前一樹梅，爲誰零落爲誰開。',32,'全唐诗/poet.song.33000.json','["白玉堂前一樹梅，爲誰零落爲誰開。", "唯有春風最相惜，一年一度一歸來。"]'),
('6933fc8d-a255-482a-8501-4bb6144f7f5a','即事五首  其一','王安石','宋','宋诗','song-poetry','','[]','漸老逢春能幾回，蓬門今始爲君開。',32,'全唐诗/poet.song.33000.json','["漸老逢春能幾回，蓬門今始爲君開。", "莫嫌野外無供給，更向花前把一杯。"]'),
('a7456c50-20d7-4fd3-9f1a-df986859d3f4','即事五首  其二','王安石','宋','宋诗','song-poetry','','[]','一樹籠鬆玉刻成，遊蜂多思正經營。',32,'全唐诗/poet.song.33000.json','["一樹籠鬆玉刻成，遊蜂多思正經營。", "攀枝弄雪時回顧，還繞櫻桃樹下行。"]'),
('5e417bdd-b7b6-449a-98b5-b3d9b1d83763','即事五首  其三','王安石','宋','宋诗','song-poetry','','[]','幽棲地僻經過少，鍾梵聲中掩竹門。',32,'全唐诗/poet.song.33000.json','["幽棲地僻經過少，鍾梵聲中掩竹門。", "唯有多情枝上雪，暗香浮動月黄昏。"]'),
('449fe7f8-775f-467f-9b7b-05d8cf4e2ba8','即事五首  其四','王安石','宋','宋诗','song-poetry','','[]','遮莫鄰鷄下五更，願爲閑客此閑行。',32,'全唐诗/poet.song.33000.json','["遮莫鄰鷄下五更，願爲閑客此閑行。", "欲知前面花多少，顛倒青苔落絳英。"]'),
('ce9dda65-cf97-40fb-8a07-d790b2de3f04','即事五首  其五','王安石','宋','宋诗','song-poetry','','[]','春光冉冉歸何處，細雨斜風作夜寒。',32,'全唐诗/poet.song.33000.json','["春光冉冉歸何處，細雨斜風作夜寒。", "猶有數葩紅好處，老年花似霧中看。"]'),
('05d18d57-d19f-4d63-ba59-b7d0574b8305','春風','王安石','宋','宋诗','song-poetry','','[]','春風吹園雜花開，青天露坐始此迴。',64,'全唐诗/poet.song.33000.json','["春風吹園雜花開，青天露坐始此迴。", "一杯一杯復一杯，笑言溢口何歡咍。", "古人白骨生青苔，我獨不飲何爲哉。", "何時出得禁酒國，壘麴便築糟丘臺。"]'),
('1c198b41-1311-4105-96ce-8b0e71fe1449','春雪','王安石','宋','宋诗','song-poetry','','[]','春雪墮如簁，渾家醉不知。',24,'全唐诗/poet.song.33000.json','["春雪墮如簁，渾家醉不知。", "泥留虎鬥迹，愁殺路傍兒。"]'),
('ab984434-8870-452c-85af-cba70091b2b9','花下','王安石','宋','宋诗','song-poetry','','[]','花下一壺酒，定將誰舉杯。',24,'全唐诗/poet.song.33000.json','["花下一壺酒，定將誰舉杯。", "雪英飛落近，疑是故人來。"]'),
('467bb79b-9809-4842-89b1-fd0a3d467586','春山','王安石','宋','宋诗','song-poetry','','[]','春山春水流，曲折方屢渡。',48,'全唐诗/poet.song.33000.json','["春山春水流，曲折方屢渡。", "荒乘不知疲，行到水窮處。", "依然舊童子，要予竹西去。", "歸時始覺遠，草蔓已多露。"]'),
('98fc9cee-9c18-4339-b462-019a4bc2d76d','金陵懷古','王安石','宋','宋诗','song-poetry','','[]','六代豪華空處所，金陵王氣黯然收。',64,'全唐诗/poet.song.33000.json','["六代豪華空處所，金陵王氣黯然收。", "煙濃草遠望不盡，物換星移度幾秋。", "至竟江山誰是主，却因歌舞破除休。", "我來不見當時事，上盡重城更上樓。"]'),
('51fd6fd0-0251-4a66-bfe2-21da2fa9edfe','沈坦之將歸溧陽值雨留吾廬久之三首  其一','王安石','宋','宋诗','song-poetry','','[]','天雨蕭蕭滯茅屋，冷猿秋雁不勝悲。',32,'全唐诗/poet.song.33000.json','["天雨蕭蕭滯茅屋，冷猿秋雁不勝悲。", "床床屋漏無乾處，獨立蒼茫自咏詩。"]'),
('1bff1a7e-6e65-45fe-82a2-792455b42da1','沈坦之將歸溧陽值雨留吾廬久之三首  其二','王安石','宋','宋诗','song-poetry','','[]','檐雨亂淋幔，風悲蘭杜秋。',24,'全唐诗/poet.song.33000.json','["檐雨亂淋幔，風悲蘭杜秋。", "相看更促膝，人老自多愁。"]'),
('08a1de87-1399-4437-bc6d-ba061a9e64ca','沈坦之將歸溧陽值雨留吾廬久之三首  其三','王安石','宋','宋诗','song-poetry','','[]','片雲頭上黑，淅淅野風秋。',24,'全唐诗/poet.song.33000.json','["片雲頭上黑，淅淅野風秋。", "室婦嘆鳴鸛，分爲兩地愁。"]'),
('a643db06-ac28-4458-8bdc-5390b97e96c5','示蔡天啟三首  其一','王安石','宋','宋诗','song-poetry','','[]','蔡子勇成癖，能騎生馬駒。',125,'全唐诗/poet.song.33000.json','["蔡子勇成癖，能騎生馬駒。", "銛鋒瑩鷿鵜，價重百硨磲。", "脫身事幽討，禪龕只晏如。", "劃然變軒昂，慎勿學哥舒。", "蔡子勇成癖，劍可萬人敵。", "讀書百紙過，穎銳物不隔。", "開口取將相，志氣方自得。", "偪仄何偪仄，未見有一獲。", "蕭條兩翅蓬蒿下，未能生彼升天翼。", "焉能學堂上燕，絢練新羽翮。"]'),
('8ba09d23-5b6e-494b-a82a-f29bb162dd24','示蔡天啟三首  其二','王安石','宋','宋诗','song-poetry','','[]','身著青衫騎惡馬，日馳三百尚嫌遲。',32,'全唐诗/poet.song.33000.json','["身著青衫騎惡馬，日馳三百尚嫌遲。", "心源落落堪爲將，却是君王未備知。"]'),
('49ef5df8-63e8-47eb-881c-7879f660f0bf','烝然來思','王安石','宋','宋诗','song-poetry','','[]','念我獨兮，亦莫我顧。',96,'全唐诗/poet.song.33000.json','["念我獨兮，亦莫我顧。", "烝然來思，程伯休父。", "我有旨酒，爾殽伊脯。", "酌言酬之，式歌且舞。", "不留不處，適彼樂土。", "言秣其馬，率西水滸。", "有客宿宿，于時語語。", "山有橋松江有渚，式遄其歸不我與。", "作此好歌，倡予和女。"]'),
('89d4cd1b-65cb-4f97-9ae9-f5c5e2d4cd4a','示楊德逢','王安石','宋','宋诗','song-poetry','','[]','我行其野，春日遲遲。',110,'全唐诗/poet.song.33000.json','["我行其野，春日遲遲。", "有菀者柳，在水之湄。", "有鳴倉庚，豈曰不時。", "求其友聲，頡之頏之。", "嗟我懷人，何日忘之。", "六日不詹，方何爲期。", "期逝不至，我心西悲。", "跂予望之，其室則邇。", "一者之來，我心則喜。", "我之懷矣，升彼虛矣。", "愛而不見，云何吁矣。"]'),
('46cbe061-c120-4d6c-bef7-8cf304df5403','示道光及安大師','王安石','宋','宋诗','song-poetry','','[]','春日載陽，陟彼高岡。',90,'全唐诗/poet.song.33000.json','["春日載陽，陟彼高岡。", "樂彼之園，維水泱泱。", "維筍及蒲，既生既育。", "拚飛維鳥，集于灌木。", "嚶其鳴矣，亂我心曲。", "有懷二人，在彼空谷。", "既往既來，獨寐寤宿。", "陟則在巘，或降于阿。", "瞻望弗及，傷如之何。"]'),
('be0bfbe0-fefe-4943-b3f7-9046ccf88473','老人行','王安石','宋','宋诗','song-poetry','','[]','老人低心逐年少，年少還爲老人調。',64,'全唐诗/poet.song.33000.json','["老人低心逐年少，年少還爲老人調。", "兩家挾詐自相欺，四海傷真誰復誚。", "翻手作雲覆手雨，當面輸心背面笑。", "古來人事已如此，今日何須論久要。"]'),
('c8e40523-5d13-40b1-9af4-bee0b5537471','離昇州作','王安石','宋','宋诗','song-poetry','','[]','相看不忍發，慘澹暮潮平。',24,'全唐诗/poet.song.33000.json','["相看不忍發，慘澹暮潮平。", "語罷更携手，月明洲渚生。"]'),
('5076c83e-288f-4028-8aa5-a27624999c3d','倉頡','王安石','宋','宋诗','song-poetry','','[]','倉頡造書，不詁自明。',20,'全唐诗/poet.song.33000.json','["倉頡造書，不詁自明。", "於乎多言，祇誤後生。"]'),
('a95233c0-df47-4696-bbfc-adce17989291','胡笳十八拍十八首  其一','王安石','宋','宋诗','song-poetry','','[]','中郎有女能傳業，顔色如花命如葉。',64,'全唐诗/poet.song.33000.json','["中郎有女能傳業，顔色如花命如葉。", "命如葉薄將奈何，一生抱恨常咨嗟。", "良人持戟明光裏，所慕靈妃媲簫史。", "空房寂寞施繐帷，棄我不待白頭時。"]'),
('fe611dd0-9097-4bb7-b242-ec6646b5ddb2','胡笳十八拍十八首  其二','王安石','宋','宋诗','song-poetry','','[]','天不仁兮降亂離，嗟余去此其從誰。',64,'全唐诗/poet.song.33000.json','["天不仁兮降亂離，嗟余去此其從誰。", "自胡之反持干戈，翠蕤雲旓相蕩摩。", "流星白羽腰間插，疊鼓遥翻瀚海波。", "一門骨肉散百草，安得無淚如黄河。"]'),
('1c679e8e-eaec-4f90-b83c-455e0f5a92e5','胡笳十八拍十八首  其三','王安石','宋','宋诗','song-poetry','','[]','身執略兮入西關，關山阻脩兮行路難。',65,'全唐诗/poet.song.33000.json','["身執略兮入西關，關山阻脩兮行路難。", "水頭宿兮草頭坐，在野只教心膽破。", "更鞴彫鞍教走馬，玉骨瘦來無一把。", "幾迴拋鞚抱鞍橋，往往驚墮馬蹄下。"]'),
('96021e0a-65cf-4015-9b43-ac5765345407','胡笳十八拍十八首  其四','王安石','宋','宋诗','song-poetry','','[]','漢家公主出和親，御厨絡繹送八珍。',80,'全唐诗/poet.song.33000.json','["漢家公主出和親，御厨絡繹送八珍。", "明妃初嫁與胡時，一生衣服盡隨身。", "眼長看地不稱意，同是天涯淪落人。", "我今一食日還併，短衣數挽不掩脛。", "乃知貧賤別更苦，安得康强保天性。"]'),
('6cca3eb5-8348-484e-9fbf-fcc4a7b6c57a','胡笳十八拍十八首  其五','王安石','宋','宋诗','song-poetry','','[]','十三學得琵琶成，並幕重重卷畫屏。',80,'全唐诗/poet.song.33000.json','["十三學得琵琶成，並幕重重卷畫屏。", "一見郎來雙眼明，勸我酤酒花前傾。", "齊言此夕樂未央，豈知此聲能斷腸。", "如今正南看北斗，言語傳情不如手。", "低眉信手續續彈，彈看飛鴻勸胡酒。"]'),
('5d548ba0-12da-4593-a952-0bd85e4fa297','胡笳十八拍十八首  其六','王安石','宋','宋诗','song-poetry','','[]','青天漫漫覆長路，一紙短書無寄處。',64,'全唐诗/poet.song.33000.json','["青天漫漫覆長路，一紙短書無寄處。", "月下長吟久不歸，當時還見雁南飛。", "彎弓射飛無遠近，青塚路邊南雁盡。", "兩處音塵從此絕，唯向東西望明月。"]'),
('6e900272-346e-4dfa-8c4b-03a39b4f2518','胡笳十八拍十八首  其七','王安石','宋','宋诗','song-poetry','','[]','明明漢月空相識，道路只今多擁隔。',64,'全唐诗/poet.song.33000.json','["明明漢月空相識，道路只今多擁隔。", "去住彼此無消息，時獨看雲淚橫臆。", "豺狼喜怒難姑息，自倚紅顔能騎射。", "千言萬語無人會，漫倚文章真末策。"]'),
('87245285-b2fa-4a6a-b8a9-e0475cf5e941','胡笳十八拍十八首  其八','王安石','宋','宋诗','song-poetry','','[]','死生難有却回身，不忍重看舊寫真。',64,'全唐诗/poet.song.33000.json','["死生難有却回身，不忍重看舊寫真。", "暮去朝來顔色改，四時天氣總愁人。", "東風漫漫吹桃李，盡日獨行春色裏。", "自經喪亂少睡眠，鶑飛燕語長悄然。"]'),
('41e44c46-dc51-449d-9fd6-f9f07d3bea33','胡笳十八拍十八首  其九','王安石','宋','宋诗','song-poetry','','[]','柳絮已將春去遠，攀條弄芳畏晼晚。',128,'全唐诗/poet.song.33000.json','["柳絮已將春去遠，攀條弄芳畏晼晚。", "憂患衆兮歡樂鮮，一去可憐終不返。", "日夕思歸不得歸，山川滿目淚沾衣。", "罼圭苑裏西風起，嘆息人間萬事非。", "寒聲一夜傳刁斗，雲雪埋山蒼兕吼。", "詩成吟咏轉凄凉，不如獨坐空搔首。", "漫漫胡天叫不聞，胡人高鼻動成群。", "寒盡春生洛陽殿，回首何時復來見。"]'),
('cb4756fc-88dc-4dc0-aca5-db77f60a864f','胡笳十八拍十八首  其一○','王安石','宋','宋诗','song-poetry','','[]','晚來幽獨恐傷神，唯見沙蓬水柳春。',65,'全唐诗/poet.song.33000.json','["晚來幽獨恐傷神，唯見沙蓬水柳春。", "破除萬事無過酒，虜酒千杯不醉人。", "含情欲說更無語，一生長恨奈何許。", "饑對酪肉兮不能餐，强來前帳臨歌舞。"]'),
('8ec917d7-bbd0-4cff-9a52-66eb77cabe27','胡笳十八拍十八首  其一一','王安石','宋','宋诗','song-poetry','','[]','歸來展轉到五更，起看北斗天未明。',64,'全唐诗/poet.song.33000.json','["歸來展轉到五更，起看北斗天未明。", "秦人築城備胡處，擾擾唯有牛羊聲。", "萬里飛蓬映天過，風吹漢地衣裳破。", "欲往城南望城北，三步回頭五步坐。"]'),
('47b3a168-3b0b-437a-abe7-5ca8718d7e18','胡笳十八拍十八首  其一二','王安石','宋','宋诗','song-poetry','','[]','自斷此生休問天，生得胡兒擬棄捐。',64,'全唐诗/poet.song.33000.json','["自斷此生休問天，生得胡兒擬棄捐。", "一始扶床一初坐，抱携撫視皆可憐。", "寧知遠使問名姓，引袖拭淚悲且慶。", "悲莫悲于生別離，悲在君家留二兒。"]'),
('53e2e060-9f4e-4d7f-a360-dc651b180975','胡笳十八拍十八首  其一三','王安石','宋','宋诗','song-poetry','','[]','鞠之育之不羞耻，恩情亦各言其子。',67,'全唐诗/poet.song.33000.json','["鞠之育之不羞耻，恩情亦各言其子。", "天寒日暮山谷裏，腸斷非關隴頭水。", "兒呼母兮啼失聲，依然離別難爲情。", "灑血仰頭兮訴蒼蒼，知我如此兮不如無生。"]'),
('c1b6eaf6-aa67-4f96-98f4-9417ecb3ddb2','胡笳十八拍十八首  其一四','王安石','宋','宋诗','song-poetry','','[]','當時悔來歸又恨，洛陽宮殿焚燒盡。',64,'全唐诗/poet.song.33000.json','["當時悔來歸又恨，洛陽宮殿焚燒盡。", "紛紛黎庶逐黄巾，心折此時無一寸。", "慟哭秋原何處村，千家今有百家存。", "爭持酒食來相饋，舊事無人可共論。"]'),
('d1be6092-fd77-4598-b2af-9b0b8ff3a5a8','胡笳十八拍十八首  其一五','王安石','宋','宋诗','song-poetry','','[]','此身飲罷無歸處，心懷百憂復千慮。',93,'全唐诗/poet.song.33000.json','["此身飲罷無歸處，心懷百憂復千慮。", "天翻地覆誰得知，魏公垂淚嫁文姬。", "天涯憔悴身，託命於新人。", "念我出腹子，使我嘆恨勞精神。", "新人新人聽我語，我所思兮在何所。", "母子分離兮意難任，死生不相知兮何處尋。"]'),
('7412c72b-1099-44a5-9e4c-4fd6ea6cbc36','胡笳十八拍十八首  其一六','王安石','宋','宋诗','song-poetry','','[]','燕山雪花大如席，與兒洗面作光澤。',64,'全唐诗/poet.song.33000.json','["燕山雪花大如席，與兒洗面作光澤。", "怳然天地半夜白，閨中祇是空相憶。", "點注桃花舒小紅，與兒洗面作華容。", "欲問平安無使來，桃花依舊笑春風。"]'),
('27ce3503-ea69-4db4-9654-9e55b225d57a','胡笳十八拍十八首  其一七','王安石','宋','宋诗','song-poetry','','[]','春風似舊花仍笑，人生豈得長年少。',100,'全唐诗/poet.song.33000.json','["春風似舊花仍笑，人生豈得長年少。", "我與兒兮各一方，憔悴看成兩鬢霜。", "如今豈無騕褭與驊騮，安得送我置汝傍。", "胡塵暗天道路長，遂令再往之計墮眇芒。", "胡笳本出自胡中，此曲哀怨何時終。", "笳一會兮琴一拍，此心炯炯君應識。"]'),
('59cae7fb-a2f0-4de4-94a2-1ec1dcb5b6e2','虞美人','王安石','宋','宋诗','song-poetry','','[]','虞美人，態濃意遠淑且真。',148,'全唐诗/poet.song.33000.json','["虞美人，態濃意遠淑且真。", "同輦隨君侍君側，六宮粉黛無顔色。", "楚歌四面起，形勢反蒼黄。", "夜聞馬嘶曉無迹，蛾眉蕭颯如秋霜。", "漢家離宮三十六，緩歌慢舞凝絲竹。", "人間舉眼盡堪悲，獨在陰崖結茅屋。", "美人爲黄土，草木皆含愁。", "紅房紫莟處處有，聽曲低昂如有求。", "青天漫漫覆長路，今人犁田昔人墓。", "虞兮虞兮奈若何，不見玉顔空死處。"]'),
('b0234d63-8770-465a-bd0e-1af0fdbb349c','潭州新學詩','王安石','宋','宋诗','song-poetry','','[]','有嘉新學，潭守所作。',210,'全唐诗/poet.song.33000.json','["有嘉新學，潭守所作。", "守者誰歟，仲庶氏吳。", "振養矜寡，衣之褰襦。", "黔首鼓歌，吏靜不求。", "乃相廟序，生師所廬。", "上漏旁穿，燥濕不除。", "曰嘻遷哉，迫阨卑污。", "當其壞時，適可以謀。", "營地慮工，伐楩楠櫧。", "撤故就新，爲此渠渠。", "潭人來止，相語而喜。", "我知視成，無豫經始。", "公升在堂，從者如水。", "公曰誨汝，潭之士子。", "古之讀書，凡以爲己。", "躬行孝悌，由義而仕。", "神聽汝助，況於閭里。", "無實而荂，非聖自是。", "雖大得意，吾猶汝耻。", "士下其手，公言無尤。", "請詩我歌，以遠公休。"]'),
('50510bfd-1909-46aa-ac24-53bfbce7d8d9','新田詩','王安石','宋','宋诗','song-poetry','','[]','離離新田，其下流水。',140,'全唐诗/poet.song.33000.json','["離離新田，其下流水。", "孰知其初，灌莽千里。", "其南背江，其北逾淮。", "父抱子扶，十百其來。", "其來僕僕，鏝我新屋。", "趙侯劬之，作者不饑。", "歲仍大熟，飽及雞鶩。", "僦船與車，四鄙出穀。", "今游者處，昔止者流。", "維昔牧我，不如今侯。", "侯來適野，不有觀者。", "稅于水濱，問我鰥寡。", "侯其歸矣，三歲于茲。", "誰能止侯，我往求之。"]'),
('e7d46de4-f0c2-422a-985c-e6753deb09d2','獵較詩','王安石','宋','宋诗','song-poetry','','[]','獵較獵較，誰禽我有。',40,'全唐诗/poet.song.33000.json','["獵較獵較，誰禽我有。", "國人之惏，君子所醜。", "獵較獵較，祭占其祥。", "國人之序，君子何傷。"]'),
('970dbd8a-dce8-40e3-8ff5-883ed86e8991','雲之祁祁答董傳','王安石','宋','宋诗','song-poetry','','[]','雲之祁祁，或雨于淵。',80,'全唐诗/poet.song.33000.json','["雲之祁祁，或雨于淵。", "苗之翹翹，或槁于田。", "雲之祁祁，或雨于野。", "有槁于田，豈不自我。", "薈兮其隮，其在西郊。", "匪我爲之，我歌且謠。", "蔚兮其復，南山之側。", "我歌且謠，維以育德。"]'),
('522f29ab-4d85-4b10-ab2e-13f71d0e6733','明堂樂章二首 歆安之曲','王安石','宋','宋诗','song-poetry','','[]','穆穆在堂，肅肅在庭。',40,'全唐诗/poet.song.33000.json','["穆穆在堂，肅肅在庭。", "於顯辟公，來相思成。", "神既歆止，有聞惟馨。", "錫我休嘉，燕及群生。"]'),
('c389f15a-1578-42a2-8754-49b577637cc7','明堂樂章二首 皇帝還大次憩安之曲','王安石','宋','宋诗','song-poetry','','[]','有奕明堂，萬方時會。',40,'全唐诗/poet.song.33000.json','["有奕明堂，萬方時會。", "宗予聖考，作帝之配。", "樂酌虞典，禮從周制。", "釐事既成，於皇來塈。"]'),
('70c93612-7acc-4b28-a204-f2fc52e9a671','得孫正之詩因寄呈曾子固','王安石','宋','宋诗','song-poetry','','[]','一歲已闌人意倦，出門風物更蕭然。',64,'全唐诗/poet.song.33000.json','["一歲已闌人意倦，出門風物更蕭然。", "水摇疏樹荒城路，日带浮雲欲雪天。", "未有詩書論進退，謾期身世託林泉。", "因思漠北離群久，此日窮居頼見賢。"]'),
('71c3e391-ab1f-40d7-8a81-7342c7e84779','和金陵懷古','王安石','宋','宋诗','song-poetry','','[]','懷鄉訪古事悠悠，獨上江城滿目秋。',64,'全唐诗/poet.song.33000.json','["懷鄉訪古事悠悠，獨上江城滿目秋。", "一鳥带煙來別渚，數帆和雨下歸舟。", "蕭蕭暮吹驚紅葉，慘慘寒雲壓舊樓。", "故國凄凉誰與問，人心無復更風流。"]'),
('d250bec9-36ac-466d-95f1-27548a45e817','豫章道中次韵答曾子固','王安石','宋','宋诗','song-poetry','','[]','離別何言邂逅同，今知相逐似雲龍。',64,'全唐诗/poet.song.33000.json','["離別何言邂逅同，今知相逐似雲龍。", "蒼煙白霧千山合，綠樹青天一水容。", "已謝道塗多自放，將歸田里更誰從。", "龐公有意安巢穴，肯問簞瓢與萬鍾。"]'),
('449d5b8a-a404-4816-a068-6b0b2c72b57d','離北山寄平甫','王安石','宋','宋诗','song-poetry','','[]','日月沄沄與水爭，披襟照見髮華驚。',64,'全唐诗/poet.song.33000.json','["日月沄沄與水爭，披襟照見髮華驚。", "少年憂患傷豪氣，老去經綸誤半生。", "休向朝廷論一鶚，只知田里守三荆。", "清溪幾曲春風好，已約歸時載酒行。"]'),
('874dcf8e-e2c9-483f-aa7e-f763587e3799','答孫正之','王安石','宋','宋诗','song-poetry','','[]','無才處處是窮塗，兩地誰傳萬里書。',64,'全唐诗/poet.song.33000.json','["無才處處是窮塗，兩地誰傳萬里書。", "節物崢嶸催歲暮，溪山蕭灑入吾廬。", "南歸猶喜尋同志，北去還聞困索居。", "佳句不須論舊約，相隨陽羨有籃輿。"]'),
('5664eef3-ff52-436e-9187-ec1db43e2a20','寄程給事','王安石','宋','宋诗','song-poetry','','[]','憶昔都門手一携，春禽初向苧蘿啼。',64,'全唐诗/poet.song.33000.json','["憶昔都門手一携，春禽初向苧蘿啼。", "夢回金殿風光別，吟到銀河月影低。", "舞急錦腰迎十八，酒酣金盞照東西。", "何時得遂扁舟去，邂逅從君訪剡溪。"]'),
('160dc88f-be3a-4763-89aa-777bd2c9d8f7','寄勝之運使','王安石','宋','宋诗','song-poetry','','[]','蕭然生事委江皋，壯士何嘗似釣鼇。',64,'全唐诗/poet.song.33000.json','["蕭然生事委江皋，壯士何嘗似釣鼇。", "千里得書來見約，一朝乘興去忘勞。", "已將流景休談笑，聊爲知音破鬰陶。", "正是東風將欲發，湖山春色助揮毫。"]'),
('9b875e94-1648-406d-a187-7151ef502041','寄國清處謙','王安石','宋','宋诗','song-poetry','','[]','三江風浪隔天台，想見當時賦咏才。',64,'全唐诗/poet.song.33000.json','["三江風浪隔天台，想見當時賦咏才。", "近有高僧飛錫去，更無餘事出山來。", "猿猱歷歷窺香火，日月紛紛付劫灰。", "我欲相期談實相，東林何必謝劉雷。"]'),
('99ccdf82-00eb-4aed-90f5-c2dd9a0c6629','將至丹陽寄表民','王安石','宋','宋诗','song-poetry','','[]','曉馬駸駸路阻脩，春風漠漠上衣裘。',64,'全唐诗/poet.song.33000.json','["曉馬駸駸路阻脩，春風漠漠上衣裘。", "三年銜恤空餘息，一日忘形願少留。", "末路悲歡隨俯仰，此生身世信沉浮。", "寄聲德操家人道，炊黍吾今且暫休。"]'),
('9758685f-53bb-4080-9476-c7dbde78aa89','宿土坊驛寄孔世長','王安石','宋','宋诗','song-poetry','','[]','燒夜郊原百草荒，弊裘朝去犯嚴霜。',64,'全唐诗/poet.song.33000.json','["燒夜郊原百草荒，弊裘朝去犯嚴霜。", "殘年意象偏多感，回首風煙更異鄉。", "往返自非名利役，辛勤應見友朋傷。", "章江猶得同游處，最愛梅花蘸水香。"]'),
('1e17426f-ddac-4021-b978-42d020c22453','寄孫正之','王安石','宋','宋诗','song-poetry','','[]','南游忽忽與誰言，共笑謀生識最昏。',64,'全唐诗/poet.song.33000.json','["南游忽忽與誰言，共笑謀生識最昏。", "萬事百年能自信，一簞五鼎不須論。", "友中惟子長招隠，世上何人可避喧。", "千里秋風相望處，皖公溪上正開樽。"]'),
('2a45c0ca-86e9-4a30-978b-7b08c049e11c','道中寄吉父','王安石','宋','宋诗','song-poetry','','[]','白霧青煙入馬蹄，朝寒瑟瑟樹聲悲。',64,'全唐诗/poet.song.33000.json','["白霧青煙入馬蹄，朝寒瑟瑟樹聲悲。", "平山斷壠回環失，鳴鳥游魚上下隨。", "廟算未聞收策士，瘴鄉誰與擇軍麾。", "憂時自欲尋君語，行路何妨更有詩。"]'),
('98d99642-a0f4-40ee-8905-6c51668483bd','送孫立之赴廣西','王安石','宋','宋诗','song-poetry','','[]','十年一別兩相過，前想悲歡慷慨歌。',64,'全唐诗/poet.song.33000.json','["十年一別兩相過，前想悲歡慷慨歌。", "窮去始知風俗薄，靜來猶厭事機多。", "相期鼻目傾肝膽，誰伴溪山避網羅。", "萬里辛勤君舊識，重江應亦畏風波。"]'),
('f4fca08e-9176-428d-81e8-a36321ef9d2a','送福建張比部','王安石','宋','宋诗','song-poetry','','[]','畫船簫鼓出都時，萬里驚鷗去不追。',64,'全唐诗/poet.song.33000.json','["畫船簫鼓出都時，萬里驚鷗去不追。", "却望塵沙應駐節，會逢山水即吟詩。", "長魚俎上通三印，新茗齋中試一旗。", "只恐遠方難久滯，莫愁風物不相宜。"]'),
('d8aa7118-c547-4861-afc9-46b5735f30b6','送致政朱郎中東歸','王安石','宋','宋诗','song-poetry','','[]','平生不省問田園，白首忘懷道更尊。',64,'全唐诗/poet.song.33000.json','["平生不省問田園，白首忘懷道更尊。", "已上印書通北闕，稍留冠蓋餞東門。", "馮唐老有爲郎戀，疏廣終無任子恩。", "今日榮歸人所羨，兩兒腰綬擁高軒。"]'),
('00c2d3db-edce-4096-9d45-1365ee93a875','別雷國輔之皖山','王安石','宋','宋诗','song-poetry','','[]','侍郎憂國最賢勞，太尉西州第一豪。',64,'全唐诗/poet.song.33000.json','["侍郎憂國最賢勞，太尉西州第一豪。", "家廟比來聞澤厚，公孫今果見才高。", "明時尚使龍蛇蟄，壯志空傳虎豹韜。", "莫厭皖山窮絕處，不妨雲水助風騷。"]'),
('7d2d3841-d95d-4ccd-af34-5339494ec0d9','垂虹亭','王安石','宋','宋诗','song-poetry','','[]','坐覺塵襟一夕空，人間似得羽翰通。',64,'全唐诗/poet.song.33000.json','["坐覺塵襟一夕空，人間似得羽翰通。", "暮天窈窈山銜日，爽氣駸駸客御風。", "草木韵沉高下外，星河影落有無中。", "飄然更待乘桴伴，一到扶桑興未窮。"]'),
('7a31a00d-8da6-46e7-9641-a37a53e1b2e6','題正覺相上人籜龍軒','王安石','宋','宋诗','song-poetry','','[]','風玉蕭蕭數畝秋，籜龍名爲道人留。',64,'全唐诗/poet.song.33000.json','["風玉蕭蕭數畝秋，籜龍名爲道人留。", "不須乞米供高士，但與開軒作勝游。", "此地七賢誰笑傲，何時六逸自賡酬。", "侵尋衰境心無著，尚有家風似子猷。"]'),
('92fca509-eb07-4770-b9bd-bfbcf898c70f','題友人壁','王安石','宋','宋诗','song-poetry','','[]','茆檐前後欠松蘿，百里乘閑向此過。',64,'全唐诗/poet.song.33000.json','["茆檐前後欠松蘿，百里乘閑向此過。", "澗水繞田山影轉，野林留日鳥聲和。", "蕭條雞犬逢人少，想象乾坤發興多。", "世事不如閑靜處，知君出處意如何。"]'),
('4c5e4876-cedc-4f35-85cd-d138614f9636','清明輦下懷金陵','王安石','宋','宋诗','song-poetry','','[]','春陰天氣草如煙，時有飛花舞道邊。',64,'全唐诗/poet.song.33000.json','["春陰天氣草如煙，時有飛花舞道邊。", "院落日長人寂寂，池塘風慢鳥翩翩。", "故園回首三千里，新火傷心六七年。", "青蓋皂衫無復禁，可能乘興酒家眠。"]'),
('4f781e1a-44fe-4001-9f00-92c3cdb0cdcb','杭州呈勝之','王安石','宋','宋诗','song-poetry','','[]','游觀須知此地佳，紛紛人物敵京華。',64,'全唐诗/poet.song.33000.json','["游觀須知此地佳，紛紛人物敵京華。", "林巒臘雪千家水，城郭春風二月花。", "彩舫笙簫吹落日，畫樓燈燭映殘霞。", "如君援筆宜摹寫，寄與塵埃北客誇。"]'),
('24444395-33ae-45c7-a923-70f056666900','聞和甫補池掾','王安石','宋','宋诗','song-poetry','','[]','遭時何必問功名，自古難將力命爭。',64,'全唐诗/poet.song.33000.json','["遭時何必問功名，自古難將力命爭。", "萬戶侯多歸世胄，五車書獨負家聲。", "才華汝尚爲丞掾，老懶吾今合釣耕。", "外物悠悠無得喪，春郊終日待相迎。"]'),
('59f144e6-e7a6-456f-bdc6-292ffee21821','寶應二三進士見送乞詩','王安石','宋','宋诗','song-poetry','','[]','少喜功名盡坦塗，那知干世最崎嶇。',64,'全唐诗/poet.song.33000.json','["少喜功名盡坦塗，那知干世最崎嶇。", "草廬有客歌梁甫，狗監無人薦子虛。", "解玩山川消積憤，靜忘歲月頼群書。", "慚君枉蓋如平昔，不笑謀生萬事疏。"]'),
('86507b69-0957-4d33-bd9f-ecc5c4963cff','謝郟亶秘校見訪於鍾山之廬','王安石','宋','宋诗','song-poetry','','[]','誤有聲名只自慚，煩君跋馬過茅檐。',64,'全唐诗/poet.song.33000.json','["誤有聲名只自慚，煩君跋馬過茅檐。", "已知原憲貧非病，更許莊周知養恬。", "世事何時逢坦蕩，人情隨分值猜嫌。", "誰能胸臆無塵滓，使我相從久未厭。"]'),
('9b19d08b-5ee9-426d-8b30-425db993c360','同長安君鍾山望','王安石','宋','宋诗','song-poetry','','[]','解裝相值得留連，一望江南萬里天。',64,'全唐诗/poet.song.33000.json','["解裝相值得留連，一望江南萬里天。", "殘雪離披山韞玉，新陽杳靄草含煙。", "餘生不足償多病，樂事應須委少年。", "惟有愛詩心未已，東歸與續棣華篇。"]'),
('ad4eb894-0e9e-4007-ac2f-834b698e79e9','奉招吉甫','王安石','宋','宋诗','song-poetry','','[]','經綸無地委蓬蒿，凜凜胸懷且自韜。',64,'全唐诗/poet.song.33000.json','["經綸無地委蓬蒿，凜凜胸懷且自韜。", "誰奮長謀平嶺海，猶將餘力寄風騷。", "名慚隨俗貧中役，恨未收身物外高。", "永夜西堂霜月冷，邀君相伴有松醪。"]'),
('37e855a6-8dc4-4d2c-b197-7d860d7feb8d','閑居遣興','王安石','宋','宋诗','song-poetry','','[]','慘慘秋陰綠樹昏，荒城高處閉柴門。',64,'全唐诗/poet.song.33000.json','["慘慘秋陰綠樹昏，荒城高處閉柴門。", "愁消日月忘身世，靜對溪山憶酒樽。", "南去干戈何日解，東來馹騎此時奔。", "誰將天下安危事，一把詩書子細論。"]'),
('c50cd36e-b17d-44bd-9122-1483a4de714f','到家','王安石','宋','宋诗','song-poetry','','[]','五年羈旅倦風埃，舊里依然似夢回。',64,'全唐诗/poet.song.33000.json','["五年羈旅倦風埃，舊里依然似夢回。", "猿鳥不須懷悵望，溪山應亦笑歸來。", "身閑自覺貧無累，命在誰論進有材。", "秋晚吾廬更蕭灑，沙邊煙樹綠洄洄。"]'),
('06f140e4-e00f-4bdd-bcae-29ef98b27d0d','西帥','王安石','宋','宋诗','song-poetry','','[]','吾君英睿超光武，良將西征捍隗囂。',64,'全唐诗/poet.song.33000.json','["吾君英睿超光武，良將西征捍隗囂。", "誓斬郅支聊出塞，生擒頡利始歸朝。", "一丸豈慮封函谷，千騎無由飲渭橋。", "好立功名標竹素，莫教空說霍嫖姚。"]'),
('02cc6f9f-7b5d-4197-ab62-4f4c24988e7f','松江','王安石','宋','宋诗','song-poetry','','[]','宛宛虹霓墮半空，銀河直與此相通。',64,'全唐诗/poet.song.33000.json','["宛宛虹霓墮半空，銀河直與此相通。", "五更縹緲千山月，萬里凄凉一笛風。", "鷗鷺稍回青靄外，汀洲時起綠蕪中。", "騷人自欲留佳句，忽憶君詩思已窮。"]'),
('ab6e6a46-c8d6-443b-a988-71fae28e7593','鳳凰山','王安石','宋','宋诗','song-poetry','','[]','歡樂欲與少年期，人生百年常苦遲。',64,'全唐诗/poet.song.33000.json','["歡樂欲與少年期，人生百年常苦遲。", "白頭富貴何所用，氣力但爲憂勤衰。", "願爲五陵輕薄兒，生在貞觀開元時。", "鬥鷄走犬過一生，天地安危兩不知。"]'),
('03f4ef34-5e5b-4982-b7a5-9cbe6a767cba','揚雄','王安石','宋','宋诗','song-poetry','','[]','孔孟如日月，委蛇在蒼旻。',96,'全唐诗/poet.song.33000.json','["孔孟如日月，委蛇在蒼旻。", "光明所照耀，萬物成冬春。", "揚子出其後，仰攀忘賤貧。", "衣冠渺塵土，文字爛星辰。", "歲晚天祿閣，强顔爲劇秦。", "趨捨迹少邇，行藏意終鄰。", "壤壤外逐物，紛紛輕用身。", "往者或可返，吾將與斯人。"]'),
('bdfa538a-eb09-4700-86e6-f987136d8c0a','寓言六首  其一','王安石','宋','宋诗','song-poetry','','[]','父母子所養，子肥父母充。',48,'全唐诗/poet.song.33000.json','["父母子所養，子肥父母充。", "欲富搉其子，惜哉術之窮。", "霸者擅一方，窘彼足自豐。", "四海皆吾家，奈何不知農。"]'),
('c874ee22-7bf7-42e3-b423-cbdd79fb6de4','寓言六首  其二','王安石','宋','宋诗','song-poetry','','[]','小夫謹利害，不講義與仁。',48,'全唐诗/poet.song.33000.json','["小夫謹利害，不講義與仁。", "讀書疑夷齊，古豈有此人。", "其才一莛芒，所欲勢萬鈞。", "求多卒自困，餘禍及生民。"]'),
('afafc006-bdfb-4743-8ac6-754e2e8f37d9','寓言六首  其三','王安石','宋','宋诗','song-poetry','','[]','瞢瞢俗所共，察察與世違。',48,'全唐诗/poet.song.33000.json','["瞢瞢俗所共，察察與世違。", "違世有百善，一疵惡皆歸。", "就求無所得，猶以好名譏。", "彼哉負且乘，能使正日微。"]'),
('fcfb0f28-fe81-4529-b5f5-47a4b6f54204','寓言六首  其四','王安石','宋','宋诗','song-poetry','','[]','始就詩賦科，雕鎸久才成。',48,'全唐诗/poet.song.33000.json','["始就詩賦科，雕鎸久才成。", "一朝復棄之，刀筆事刑名。", "中材蔽末學，斯道苦難明。", "忽貴不自期，何施就升平。"]'),
('7377fbea-8c6e-42eb-8144-f75ba50c4577','寓言六首  其五','王安石','宋','宋诗','song-poetry','','[]','明者好自蔽，況乃知我匹。',48,'全唐诗/poet.song.33000.json','["明者好自蔽，況乃知我匹。", "每行悔其然，所見定萬一。", "不求攻爾短，欲議世之失。", "耘而舍其田，辛苦亦何實。"]'),
('1944aee6-4c97-46f7-8e8b-47616c64607e','寓言六首  其六','王安石','宋','宋诗','song-poetry','','[]','好樂世所共，欲禁安能捨。',48,'全唐诗/poet.song.33000.json','["好樂世所共，欲禁安能捨。", "孰能開其淫，要在習以雅。", "敺人必如己，墨子見何寡。", "惜哉後世音，至美不如野。"]'),
('7174c1c1-a104-4387-8caa-a0b7a6b725d5','澶州','王安石','宋','宋诗','song-poetry','','[]','津津河北流，嶭嶭兩城峙。',168,'全唐诗/poet.song.33000.json','["津津河北流，嶭嶭兩城峙。", "春秋諸侯會，澶淵乃其地。", "書留後世法，豈獨譏當世。", "野老豈知此，爲予談近事。", "邊關一失守，北望皆胡騎。", "黄屋親乘城，穹廬矢如蝟。", "紛紜擅將相，誰爲開長利。", "焦頭收末功，尚足誇一是。", "歡盟從此數，日月行人至。", "馳迎傳馬單，走送牛車疲。", "征求事供給，廝養猶珍麗。", "戈甲久已銷，澶人益憔悴。", "能將大事小，自合文王意。", "語翁無嘆嗟，小雅今不廢。"]'),
('742f4449-b437-468d-8ce9-f4c143f450d7','寄平甫弟衢州道中','王安石','宋','宋诗','song-poetry','','[]','淺溪受日光烱碎，野林參天陰翳長。',64,'全唐诗/poet.song.33000.json','["淺溪受日光烱碎，野林參天陰翳長。", "幽鳥不見但聞語，小梅欲空猶有香。", "長年無可自娛戲，遠遊雖好更悲傷。", "安得冬風一吹汝，手把詩書來我旁。"]'),
('291affcb-c80b-404d-b5a8-af95850d0bf7','寄慎伯筠','王安石','宋','宋诗','song-poetry','','[]','世網掛士如蛛絲，大不及取小綴之。',224,'全唐诗/poet.song.33000.json','["世網掛士如蛛絲，大不及取小綴之。", "宜乎倜儻不低斂，醉脚踏倒青天低。", "前日才能始誰播，一口驚張萬誇和。", "雷公訴帝喘欲吹，咸恐聲名塞天破。", "文章喜以怪自娛，不肯裁縮要有餘。", "多爲峭句不姿媚，天骨老硬無皮膚。", "人傳書染莫對當，破卵驚出鸞鳳翔。", "人間下筆不肯屈，鐵索急纏蛟龍僵。", "少年意氣强不羈，虎脅插翼白日飛。", "欲將獨立誇萬世，笑誚李白爲癡兒。", "四天無壁才可家，醉膽憤癢遣酒拏。", "欲偷北斗酌竭酒，力拔太華鑣鯨牙。", "世儒口軟聲似蠅，好於壯士爲忌憎。", "我獨久仰願一見，浩歌不敢兒女聲。"]'),
('d929e572-2e9c-4fc2-8828-c684c9cac5df','望晼山馬上作','王安石','宋','宋诗','song-poetry','','[]','亙天青鬰鬰，千峰互崷崒。',120,'全唐诗/poet.song.33000.json','["亙天青鬰鬰，千峰互崷崒。", "放馬倚長崖，煙雲爭吐沒。", "遠疑嵩華低，近豈潛衡匹。", "奚爲鮮眺覽，過者輒倉卒。", "吾將凌其巔，震蕩睨溟渤。", "旁行告予言，世孰於此忽。", "邃深不可俯，儲藏盡妖物。", "踴躍狼虎群，蜿蜒蛇虺窟。", "惜哉危絕山，歲久沉汨沒。", "誰將除茀塗，萬里遊人出。"]'),
('f65dd14c-a415-4ef5-94db-2a418ec396c7','汝癭和王仲儀','王安石','宋','宋诗','song-poetry','','[]','汝水出山險，汝民多病癭。',240,'全唐诗/poet.song.33000.json','["汝水出山險，汝民多病癭。", "或如鳥粻滿，或若猿嗛並。", "女慚高掩襟，男大闊裁領。", "飲水疑注壺，吐詞侔有梗。", "樗里既已聞，杜預亦不幸。", "秦人號智囊，吳瓠掛狗頸。", "𦢏𩲞常柱頤，伶仃安及脛。", "祗欲仰問天，無由俯窺井。", "挾带歲月深，冒犯風霜冷。", "厭惡雖自知，剖割且誰肯。", "不惟羞把鏡，仍亦愁弔影。", "內療煩羊靨，外砭廢針穎。", "在木曰楠榴，刳之可曰皿。", "此誠無所用，既有何能屏。", "膨脝厠元首，臃腫異臚頂。", "難將面目施，可與胞胎逞。", "賢哉臨汝守，世德調金鼎。", "珉俗雖醜乖，教令日修整。", "風土恐隨改，晨昏憂慮省。", "儻欲覲慈顔，名城不難請。"]'),
('1dcf9fa4-29c6-465e-bcbf-cf35e601244f','三月十日韓子華招飲歸城','王安石','宋','宋诗','song-poetry','','[]','清明曉赴韓侯家，自買白杏丁香花。',112,'全唐诗/poet.song.33000.json','["清明曉赴韓侯家，自買白杏丁香花。", "雀眼塗金銀篾籠，貯在當庭呼舞娃。", "舞娃聊捧笑向客，不顧插壞新烏紗。", "朝來我舍報生子，賀勸大白浮紅霞。", "酒狂有持梧桐板，暴謔一似漁陽撾。", "袒裼擊鼓禰處士，當時偶脫猛虎牙。", "褊衷不容又何益，鸚鵡洲上空蒹葭。"]'),
('2bdfa733-a1a6-4e1d-a2ad-35bdfa4c5777','勿去草','王安石','宋','宋诗','song-poetry','','[]','勿去草，草無惡，若比世俗俗浮薄。',120,'全唐诗/poet.song.33000.json','["勿去草，草無惡，若比世俗俗浮薄。", "君不見長安公卿家，公卿盛時客如麻。", "公卿去後門無車，惟有芳草年年佳。", "又不見千里萬里江湖濱，觸目凄凄無故人。", "惟有芳草隨車輪。", "一日還舊居，門前草先鋤。", "草於主人實無負，主人於草宜何如。", "勿去草，草無惡，若比世俗俗浮薄。"]'),
('95e62d96-2acd-4019-af1a-d8e364370c3f','東城','王安石','宋','宋诗','song-poetry','','[]','昔予出東城，初見壟上耕。',48,'全唐诗/poet.song.33000.json','["昔予出東城，初見壟上耕。", "忽忽日北至，歲月良可驚。", "雖云一草死，萬物尚華榮。", "誰能當此時，嘆息微陰生。"]'),
('45d866a7-0f5b-4f21-b8d8-8f7767b6467c','哀賢亭','王安石','宋','宋诗','song-poetry','','[]','黄鳥哀子車，强埋非天爲。',96,'全唐诗/poet.song.33000.json','["黄鳥哀子車，强埋非天爲。", "天奪不待老，還能使人悲。", "馬侯東南秀，鞭策要路馳。", "歸骨萬里州，乃當强壯時。", "墓門閉空原，白日無履綦。", "蒼蒼柏與松，浩浩山風吹。", "我初羞夷吾，鮑叔亦我知。", "終欲往一慟，咏言慰孤嫠。"]'),
('28306dd0-9572-4ec5-8cd4-93c6a2bf1a60','梁王吹臺','王安石','宋','宋诗','song-poetry','','[]','繁臺繁姓人，埋滅爲蒿蓬。',120,'全唐诗/poet.song.33000.json','["繁臺繁姓人，埋滅爲蒿蓬。", "況乃漢驕子，魂遊誰肯逢。", "緬思當盛時，警蹕在虛空。", "蛾眉倚高寒，環珮吹玲瓏。", "大梁千萬家，回首雲濛濛。", "仰不見王處，雲間指青紅。", "賓客有司馬，鄒枚避其鋒。", "灑筆飛鳥上，爲王賦雌雄。", "惜今此不傳，楚辭擅無窮。", "空餘一丘土，千載播悲風。"]'),
('b5886ea3-c1fa-4d52-83e3-e49273209cfd','靈山寺','王安石','宋','宋诗','song-poetry','','[]','靈山名誰自，波濤截孤峰。',144,'全唐诗/poet.song.33000.json','["靈山名誰自，波濤截孤峰。", "何年佛子住，四面憑危空。", "折椽與裂瓦，委棄填西東。", "庫廊行抑首，居者莽誰容。", "吾舟維其側，落日生秋風。", "瞰崖聊寄目，萬物極纖穠。", "震蕩江海思，洗滌堙鬰中。", "胡爲嬉遊人，過此無留蹤。", "景豈龍遊殊，盛衰浩無窮。", "吾聞世所好，樓殿浮青紅。", "那知山水樂，豈在豪華宮。", "世好□變爾，感激難爲工。"]'),
('8301ec6a-b41c-4399-a830-0aa5d0bbc0b4','白鷗','王安石','宋','宋诗','song-poetry','','[]','江鷗好羽毛，玉雪無塵垢。',72,'全唐诗/poet.song.33000.json','["江鷗好羽毛，玉雪無塵垢。", "滅沒波浪間，生涯亦何有。", "雄雌屢驚矯，機弋常紛糾。", "顧我獨無心，相隨如得友。", "飄然紛華地，此物乖隔久。", "白髮望東南，春江綠如酒。"]'),
('286549ef-7d5f-4bac-8e57-5bcf735216e3','咏風','王安石','宋','宋诗','song-poetry','','[]','風從北海起，至此南海上。',60,'全唐诗/poet.song.33000.json','["風從北海起，至此南海上。", "問風來何事，去復欲何向。", "誰遣汝而號，誰應汝而唱。", "汝於何時息，汝作無乃妄。", "風初無一言，試以問雲將。"]'),
('35950ef8-bf0f-499c-9464-cf41bced894e','白雲','王安石','宋','宋诗','song-poetry','','[]','英英白雲浮在天，下無根蒂旁無連。',64,'全唐诗/poet.song.33000.json','["英英白雲浮在天，下無根蒂旁無連。", "西風來吹欲消散，落日起望心悠然。", "願回羲和借光景，常使秀色當檐邊。", "時來不道能爲雨，直以無心最可憐。"]'),
('865f04c2-cd8a-47e2-a74a-6c82fb9e60b2','江鄰幾邀觀三館書畫','王安石','宋','宋诗','song-poetry','','[]','五月秘府始曝書，一日江君來約予。',208,'全唐诗/poet.song.33000.json','["五月秘府始曝書，一日江君來約予。", "世間雖有古畫筆，可往共觀臨石渠。", "我時冒熱跨馬去，開厨發匣鳴鏁魚。", "羲獻墨迹十一卷，水玉作軸排疏疏。", "最奇小楷樂毅論，永和題尾付官奴。", "又有四山絕品畫，戴嵩吳牛望青蕪。", "李成寒林樹半枯，黄筌工妙白兔圖。", "不知名姓貌人物，二公對奕旁觀俱。", "黄金錯鏤爲投壺，粉幛復畫一病夫。", "後有女子執巾裾，床前紅毯平火爐。", "床上二姝展氍毹，繞床屏風山有無。", "堂上列畫三重鋪，此幅巧甚意思殊。", "孰真孰假丹青摹，世事若此還可吁。"]'),
('54dd3cb3-4e3b-4552-9eec-ebbc30f267f4','河北民','王安石','宋','宋诗','song-poetry','','[]','河北民，生近二邊長苦辛。',92,'全唐诗/poet.song.33000.json','["河北民，生近二邊長苦辛。", "家家養子學耕織，輸與官家事夷狄。", "今年大旱千里赤，州縣仍催給河役。", "老小相携來就南，南人豐年自無食。", "悲愁白日天地昏，路旁過者無顔色。", "汝生不及貞觀中，斗粟數錢無兵戎。"]'),
('f3f5c1db-d39f-4c91-9895-26c3d03427cd','君難託','王安石','宋','宋诗','song-poetry','','["\u5987\u5973", "\u54c0\u6028", "\u7231\u60c5"]','槿花朝開暮還墜，妾身與花寧獨異。',92,'全唐诗/poet.song.33000.json','["槿花朝開暮還墜，妾身與花寧獨異。", "憶昔相逢俱少年，兩情未許誰最先。", "感君綢繆逐君去，成君家計良辛苦。", "人事反復那能知，讒言入耳須臾離。", "嫁時羅衣羞更著，如今始悟君難託。", "君難託，妾亦不忘舊時約。"]'),
('1e672a3e-9f9c-40ec-b1ca-71b17ab46437','次韵張子野秋中久雨晚晴','王安石','宋','宋诗','song-poetry','','[]','天沉四山黑，池漲百泉黄。',72,'全唐诗/poet.song.33000.json','["天沉四山黑，池漲百泉黄。", "苦濕欲千里，願晴非一鄉。", "埽除供晚色，洗刷放秋光。", "菊泣花猶重，秔肥穗稍長。", "積陰消戶牖，返照媚林塘。", "想見陽臺路，神歸髮彩凉。"]'),
('8e38d870-a1f8-459e-9bf0-69da17cfc87a','射亭','王安石','宋','宋诗','song-poetry','','[]','因射構茲亭，序賢仍閱兵。',48,'全唐诗/poet.song.33000.json','["因射構茲亭，序賢仍閱兵。", "庶民觀禮教，群寇避威聲。", "城壘前相壯，溪山勢盡傾。", "宜哉百里地，桴鼓未嘗鳴。"]'),
('ee14fb31-01b4-4d04-bab2-edc5a7715b96','寄王補之','王安石','宋','宋诗','song-poetry','','[]','平居相值晚，況復道塗留。',48,'全唐诗/poet.song.33000.json','["平居相值晚，況復道塗留。", "今我思揮麈，逢君爲艤舟。", "人情方慕貴，吾道合歸休。", "吏責真難塞，聊爲泮水游。"]'),
('9faac4f9-1ee0-40f9-86ba-b50c9bd92915','寄謝師直','王安石','宋','宋诗','song-poetry','','[]','湖海三年隔，相逢塞路中。',48,'全唐诗/poet.song.33000.json','["湖海三年隔，相逢塞路中。", "黄金酌卯酒，白髮對春風。", "所願乖平日，何知即老翁。", "悠悠越溪水，好在釣魚筒。"]'),
('655decb4-b7eb-4a45-b458-4733e00b426c','次韵留題僧假山','王安石','宋','宋诗','song-poetry','','[]','態足萬峰奇，功纔一簣微。',72,'全唐诗/poet.song.33000.json','["態足萬峰奇，功纔一簣微。", "愚公誰助徙，靈鷲却愁飛。", "竇雪藏銀鎰，檐曦散玉輝。", "未應頹蟻壤，方此鎮禪扉。", "物理有真僞，僧言無是非。", "但知名盡假，不必故山歸。"]'),
('db021cae-3ebc-4830-8c24-afb231ae70c6','次韵王禹玉平戎慶捷','王安石','宋','宋诗','song-poetry','','[]','熙河形勢壓西陲，不覺連營列漢旗。',64,'全唐诗/poet.song.33000.json','["熙河形勢壓西陲，不覺連營列漢旗。", "天子坐籌星兩兩，將軍歸佩印累累。", "稱觴別殿傳新曲，銜璧名王按舊儀。", "江漢一篇猶未美，周宣方事伐淮夷。"]'),
('69bb5743-8213-44e7-bff9-c78c6ac2d311','春怨','王安石','宋','宋诗','song-poetry','','[]','掃地待花落，惜花輕著塵。',24,'全唐诗/poet.song.33000.json','["掃地待花落，惜花輕著塵。", "遊人少春戀，踏去却尋春。"]'),
('cbbb7283-ae18-4a48-8f54-7be742e1fdd2','宮詞','王安石','宋','宋诗','song-poetry','','[]','六宅新粧促錦，三宮巧仗叢花。',28,'全唐诗/poet.song.33000.json','["六宅新粧促錦，三宮巧仗叢花。", "一片黄雲起處，內人遥認官家。"]'),
('51cfa385-4c07-4108-8940-4b6cae4dfcfa','雜咏','王安石','宋','宋诗','song-poetry','','[]','百年禮樂逢休運，千里江山極勝游。',32,'全唐诗/poet.song.33000.json','["百年禮樂逢休運，千里江山極勝游。", "那似鮑昭空寫恨，不爲王粲祇消憂。"]'),
('5a47dd9d-97df-4bbc-879d-dfce1e6c37ae','晚春','王安石','宋','宋诗','song-poetry','','[]','春殘葉密花枝少，睡起茶多酒盞疏。',32,'全唐诗/poet.song.33000.json','["春殘葉密花枝少，睡起茶多酒盞疏。", "斜倚屏風搔首坐，滿簪華髮一床書。"]'),
('ef981453-52b1-4b20-ad25-6aabb89ea3d7','樓上望湖','王安石','宋','宋诗','song-poetry','','[]','樓上人腸渴欲枯，樓前終日望平湖。',32,'全唐诗/poet.song.33000.json','["樓上人腸渴欲枯，樓前終日望平湖。", "無舟得入滄浪去，爲問漁人得意無。"]'),
('ce8449f7-cb0d-49e2-b8ab-90eae2a22f9b','寄李道人','王安石','宋','宋诗','song-poetry','','[]','李生富漢亦貧兒，人不知渠只我知。',32,'全唐诗/poet.song.33000.json','["李生富漢亦貧兒，人不知渠只我知。", "跳過六輪中耍峭，養成三界外愚癡。"]'),
('b6bdc6e0-7d75-446e-bf11-0768a1ee660e','憶江南','王安石','宋','宋诗','song-poetry','','[]','城南城北萬株花，池面冰消水見沙。',32,'全唐诗/poet.song.33000.json','["城南城北萬株花，池面冰消水見沙。", "回首江南春更好，夢爲蝴蝶亦還家。"]'),
('6f6855c3-d1d1-449e-a2ae-1af555e88c0d','謝微之見過','王安石','宋','宋诗','song-poetry','','[]','此身已是一枯株，所記交朋八九無。',32,'全唐诗/poet.song.33000.json','["此身已是一枯株，所記交朋八九無。", "唯有微之來訪舊，天寒幾夕擁山爐。"]'),
('9184aad8-734d-4697-94fb-fa5bf38d1152','惜春','王安石','宋','宋诗','song-poetry','','[]','滿城風雨滿城塵，蓋紫藏紅漫惜春。',32,'全唐诗/poet.song.33000.json','["滿城風雨滿城塵，蓋紫藏紅漫惜春。", "春去自應無覓處，可憐多少惜花人。"]'),
('37b84525-200e-4452-9994-e474604e9b44','子貢','王安石','宋','宋诗','song-poetry','','[]','一來齊境助奸臣，去誤驕王亦苦辛。',32,'全唐诗/poet.song.33000.json','["一來齊境助奸臣，去誤驕王亦苦辛。", "魯國存亡宜有命，區區翻覆亦何人。"]'),
('7b68695d-2db7-4e69-b3a3-22360b6fe8d1','急足集句','王安石','宋','宋诗','song-poetry','','[]','年去年來來去忙，倚他門戶傍他牆。',32,'全唐诗/poet.song.33000.json','["年去年來來去忙，倚他門戶傍他牆。", "一封朝奏緣何事，斷盡蘇州刺史腸。"]'),
('2880d6cc-7ba7-426c-abb5-db2425c0e4ae','題定力院壁','王安石','宋','宋诗','song-poetry','','[]','溪北溪南水暗通，隔溪遥見夕陽舂。',32,'全唐诗/poet.song.33000.json','["溪北溪南水暗通，隔溪遥見夕陽舂。", "思量諸葛成何事，只合終身作卧龍。"]'),
('2992f524-941c-4911-8157-2dae54dc2ac3','題山寺扉','王安石','宋','宋诗','song-poetry','','[]','口啣天憲手持鈞，已是龍墀第一人。',32,'全唐诗/poet.song.33000.json','["口啣天憲手持鈞，已是龍墀第一人。", "回首三千大千界，此身猶是一微塵。"]'),
('30b85b83-e67f-4d9a-b75b-55bd1539cb77','字謎詩二首  其一','王安石','宋','宋诗','song-poetry','','[]','兄弟四人兩人大，一人立地三人坐。',32,'全唐诗/poet.song.33000.json','["兄弟四人兩人大，一人立地三人坐。", "家中更有一兩口，任是凶年也得過。"]'),
('377bf9cb-1bc1-4268-86d3-e815fe0ec600','字謎詩二首  其二','王安石','宋','宋诗','song-poetry','','[]','將軍身是五行精，日日燕山望石城。',32,'全唐诗/poet.song.33000.json','["將軍身是五行精，日日燕山望石城。", "待得功成身又退，空將心腹爲蒼生。"]'),
('93d1b025-6af5-43b9-9fac-b56412d82d20','用字謎','王安石','宋','宋诗','song-poetry','','[]','一月又一月，兩月共半邊。',38,'全唐诗/poet.song.33000.json','["一月又一月，兩月共半邊。", "上有可耕之田，下有長流之川。", "一家有六口，兩口不團圓。"]'),
('81aae0fa-f3d9-416b-a248-e585d95eaced','晴景','王安石','宋','宋诗','song-poetry','','[]','雨來未見花間蕊，雨後全無葉底花。',32,'全唐诗/poet.song.33000.json','["雨來未見花間蕊，雨後全無葉底花。", "蜂蝶紛紛過牆去，却疑春色在鄰家。"]'),
('6c5df472-264b-4761-b21d-4080af5598f9','題夏旼扇','王安石','宋','宋诗','song-poetry','','[]','白馬津頭驛路邊，陰森喬木带漪漣。',32,'全唐诗/poet.song.33000.json','["白馬津頭驛路邊，陰森喬木带漪漣。", "夕陽一馬匆匆過，夢寐如今十五年。"]'),
('cf7626b6-34c2-461a-ab3c-798c84675f4e','皇祐庚寅自臨川如錢塘過宿此嘉祐戊辰自番陽歸臨川再宿金峰','王安石','宋','宋诗','song-poetry','','[]','十年再宿金峰下，身世飄然豈自知。',32,'全唐诗/poet.song.33000.json','["十年再宿金峰下，身世飄然豈自知。", "山谷有靈應笑我，紛紛南北欲何爲。"]'),
('516be601-c7a7-4a19-9766-1a06606a7f9e','題金陵驛','王安石','宋','宋诗','song-poetry','','[]','重岡古道春風裏，草色花光似故人。',32,'全唐诗/poet.song.33000.json','["重岡古道春風裏，草色花光似故人。", "却喜此身今漫浪，回家隨處得相親。"]'),
('9c6337ce-2b2d-4b2b-ab49-be5cabbdc48f','咏梅','王安石','宋','宋诗','song-poetry','','[]','頗怪梅花不肯開，豈知有意待春來。',64,'全唐诗/poet.song.33000.json','["頗怪梅花不肯開，豈知有意待春來。", "燈前玉面披香出，雪後春容取勝回。", "觸撥清詩成走筆，淋漓紅袖趣傳杯。", "望塵俗眼那知此，只買夭桃艷杏栽。"]'),
('94e03500-1465-4b92-a5a0-b1bcc7cc647e','書堂','王安石','宋','宋诗','song-poetry','','[]','烏石岡頭上塚歸，柘岡西畔下書帷。',32,'全唐诗/poet.song.33000.json','["烏石岡頭上塚歸，柘岡西畔下書帷。", "辛夷花發白如雪，萬國春風慶曆時。"]'),
('d3072572-c33a-4fac-bd28-830585eda5df','海棠','王安石','宋','宋诗','song-poetry','','[]','桂寧辭月窟，桃合避仙源。',96,'全唐诗/poet.song.33000.json','["桂寧辭月窟，桃合避仙源。", "贈別難饒柳，忘憂好樹萱。", "輕輕飛燕舞，脈脈息媯言。", "蕙陋虛侵徑，梨凡浪占園。", "論心留蝶宿，低面厭鶑喧。", "不奈神仙品，何辜造化恩。", "烟愁思舊夢，雨泣怨新婚。", "畫恐明妃恨，移同卓氏奔。"]'),
('243d2dc5-de6b-4d91-b27f-688f94026b78','李花','王安石','宋','宋诗','song-poetry','','[]','朝摘桃花紅破萼，莫摘李花繁滿枝。',32,'全唐诗/poet.song.33000.json','["朝摘桃花紅破萼，莫摘李花繁滿枝。", "客心浩蕩東風急，把酒看花能幾時。"]'),
('d92d5567-880f-42f0-bdb9-4132af80aa0a','石竹花','王安石','宋','宋诗','song-poetry','','[]','麝香眠後露檀勻，繡在羅衣色未真。',32,'全唐诗/poet.song.33000.json','["麝香眠後露檀勻，繡在羅衣色未真。", "斜倚細叢如有恨，冷摇數朵欲無春。"]'),
('87b5cab7-0b5b-4cf7-bd50-5985e3ab09a2','桑','王安石','宋','宋诗','song-poetry','','[]','溪橋接桑畦，鈎籠曉群過。',24,'全唐诗/poet.song.33000.json','["溪橋接桑畦，鈎籠曉群過。", "今朝去何早，向晚蠶恐餓。"]'),
('48badbd2-9054-4464-bb7b-5e4146096934','和叔才岸傍古廟','王安石','宋','宋诗','song-poetry','','[]','樹老垂纓亂，祠荒向水開。',48,'全唐诗/poet.song.33000.json','["樹老垂纓亂，祠荒向水開。", "偶人經雨踣，古屋爲風摧。", "野鳥棲塵座，漁郎奠竹杯。", "欲傳山鬼曲，無奈楚詞哀。"]'),
('b40865db-e9c8-4e6c-989f-a56e1bac20f8','題寶巖寺寒碧亭二首  其一','王安石','宋','宋诗','song-poetry','','[]','兩岸青山刻峭成，一溪回曲篆紋平。',32,'全唐诗/poet.song.33000.json','["兩岸青山刻峭成，一溪回曲篆紋平。", "綠陰隠隠無重數，欲去黄鸝又一聲。"]'),
('86b73ccb-6fc9-446f-a796-5fb7091e239b','題寶巖寺寒碧亭二首  其二','王安石','宋','宋诗','song-poetry','','[]','風吹洞口雲，水動山頭月。',24,'全唐诗/poet.song.33000.json','["風吹洞口雲，水動山頭月。", "野老時問人，前村多少雪。"]'),
('d5fabea0-0cc6-46fa-9a0b-086d0e1c722f','同應之登大宋陂','王安石','宋','宋诗','song-poetry','','[]','望闊真多思，憑高更損神。',48,'全唐诗/poet.song.33000.json','["望闊真多思，憑高更損神。", "山川散白日，草木共青春。", "寂寂興亡事，悠悠來往人。", "素衣吳白紵，盡化洛陽塵。"]'),
('b414e040-cf37-41c5-b8c5-0a591c8da680','題回峰寺詩','王安石','宋','宋诗','song-poetry','','[]','山勢欲壓海，禪扃向此開。',48,'全唐诗/poet.song.33000.json','["山勢欲壓海，禪扃向此開。", "魚龍腥不到，日月影先來。", "樹色秋擎出，鐘聲浪答回。", "何期乘吏役，暫此拂塵埃。"]'),
('f1ed6833-1655-49e0-b54b-d83d8db44247','山居雜言','王安石','宋','宋诗','song-poetry','','[]','法和衣鉢過南華，正葉傳師萃一花。',64,'全唐诗/poet.song.33000.json','["法和衣鉢過南華，正葉傳師萃一花。", "勝地霧迷淮水石，望星人指楚天涯。", "數千松倚西山老，七百僧悲去路賒。", "一片蒼苔涅槃石，至今繚遶白雲遮。"]'),
('2846b3f2-8e46-42a9-93c5-a021ee799ada','將赴南徐任遊茅山有作','王安石','宋','宋诗','song-poetry','','[]','丹陽太守意如何，先謁茅卿始下車。',64,'全唐诗/poet.song.33000.json','["丹陽太守意如何，先謁茅卿始下車。", "展節事君三黜後，收心奉道五旬餘。", "回尋靈藥逢芝圃，欲叩真關借玉書。", "不用從人問通塞，天教吏隠接仙居。"]'),
('36df2c2c-e1ae-46ff-9a05-850fff1b6cca','題楊溪','王安石','宋','宋诗','song-poetry','','[]','橋橫葛仙陂，住近楊雄宅。',24,'全唐诗/poet.song.33000.json','["橋橫葛仙陂，住近楊雄宅。", "主人胡不歸，爲我炊香白。"]'),
('a185ddfa-141f-47bc-bb31-916a66b73020','送王郎中知江陰','王安石','宋','宋诗','song-poetry','','[]','持歸霄漢青綾被，去看吳都白馬潮。',64,'全唐诗/poet.song.33000.json','["持歸霄漢青綾被，去看吳都白馬潮。", "疊鼓渡江寒浪伏，鳴鐃入境野雲飄。", "魚穿楊柳誇鯨膾，人采芙蓉學細腰。", "家有三槐爲太守，弟兄誰似李文饒。"]'),
('bf6f8d02-5c0d-4bc7-98f4-16301e2d7ed1','挽舜元胡著作郎','王安石','宋','宋诗','song-poetry','','[]','德行文章里閈宗，姓名朝野盡知公。',64,'全唐诗/poet.song.33000.json','["德行文章里閈宗，姓名朝野盡知公。", "侍親存沒皆全孝，報政初終必竭忠。", "性直不從花縣樂，分安求逸郁堂空。", "從今永別人間去，笑入蓬瀛閬苑中。"]'),
('4f7e36a9-c85e-443e-a4bd-67725ae60b78','胡氏逢原堂','王安石','宋','宋诗','song-poetry','','[]','我愛銅官好，君實家其間。',144,'全唐诗/poet.song.33000.json','["我愛銅官好，君實家其間。", "山水相縈萃，花卉矜春妍。", "有鳴林間禽，有躍池中鮮。", "葉山何嗟峨，秀峙東南偏。", "峰巒日在望，遠色涵雲邊。", "賓客此遴集，觴飲常留連。", "君家世儒雅，子弟清風傳。", "前日闢書堂，名之曰逢原。", "有志在古道，馳情慕高賢。", "深哉堂名意，推此宜勉𣃼。", "木茂貴培本，流長思養源。", "左右無不宜，願獻小詩篇。"]'),
('6c145a07-6583-4b5b-9356-2b36e7bb5e1c','千丈巖瀑布','王安石','宋','宋诗','song-poetry','','[]','拔地萬重清嶂立，懸空千丈素流分。',32,'全唐诗/poet.song.33000.json','["拔地萬重清嶂立，懸空千丈素流分。", "共看玉女機絲挂，映日還成五色文。"]'),
('06a4523e-61cb-4e85-8893-4372260d17bd','聽泉亭','王安石','宋','宋诗','song-poetry','','[]','逗石穿雲落澗隈，無風自到枕邊來。',32,'全唐诗/poet.song.33000.json','["逗石穿雲落澗隈，無風自到枕邊來。", "十年客底黄粱夢，一夜水聲却喚回。"]'),
('01227c7b-70c0-4a2c-9115-9a75dc2c0682','句  其一','王安石','宋','宋诗','song-poetry','','[]','衰俗易高名已振，險途難盡學須强。',16,'全唐诗/poet.song.33000.json','["衰俗易高名已振，險途難盡學須强。"]'),
