('27dbb5e2-ddc7-4cf9-952b-fbbf64e0724f','存目  其一','王安石','宋','宋诗','song-poetry','','[]','詩題：黄梅花首句：庾嶺開時媚雪霜。',17,'全唐诗/poet.song.33000.json','["詩題：黄梅花首句：庾嶺開時媚雪霜。"]'),
('4399f94c-2a31-47a3-a42d-6e0fee2bb4af','存目  其二','王安石','宋','宋诗','song-poetry','','[]','詩題：梅花首句：醉筆題詩紫界牆。',16,'全唐诗/poet.song.33000.json','["詩題：梅花首句：醉筆題詩紫界牆。"]'),
('0ce48e8b-fe53-4aec-a585-6f5361bb031b','清淑堂','譚掞','宋','宋诗','song-poetry','','[]','群峰合勢曲江頭，二水交流夾一州。',32,'全唐诗/poet.song.33000.json','["群峰合勢曲江頭，二水交流夾一州。", "地有九嶷清淑氣，人無五嶺鬰蒸愁。"]'),
('df4ae1db-f1eb-4953-9e53-960a7530ce2a','月石','吳頤','宋','宋诗','song-poetry','','[]','嫦娥促輕車，翩翩下瑶城。',96,'全唐诗/poet.song.33000.json','["嫦娥促輕車，翩翩下瑶城。", "窮幽得靈山，意欲家平生。", "隳石擬素魄，神功夜無聲。", "佳桂願托根，老兔祈偕行。", "上帝聞之怒，地祇奪我睛。", "交詔責其歸，命駕涕以橫。", "事往千古後，殷勤有餘情。", "夜半纖雲收，回光對兩盈。"]'),
('9a1037cd-9960-4dc3-b4e7-3a3f4935d262','過赤石湖有感寄獻荆公','吳頤','宋','宋诗','song-poetry','','[]','重湖遠映日無光，兩槳行舟類堵牆。',64,'全唐诗/poet.song.33000.json','["重湖遠映日無光，兩槳行舟類堵牆。", "向此柂工猶恐懼，更堪風馭出蒼惶。", "雖知行止懸於命，長離憂虞亦可傷。", "白首何時裕儋石，從容丈室問空王。"]'),
('117af8b8-2f40-4c29-9aa9-1e8ca10dc916','酥花韵','吳頤','宋','宋诗','song-poetry','','[]','玉指纖纖出後房，似矜隨意得奇芳。',64,'全唐诗/poet.song.33000.json','["玉指纖纖出後房，似矜隨意得奇芳。", "只愁暖律爭先落，頼有凝脂可旋粧。", "近比含飴知有味，不須嚼蕊自聞香。", "未應力欲爭春巧，喜士深心庶可將。"]'),
('bbe29f13-206e-4a74-a769-7ac5f56e6cc1','次邦憲宣德紅梅詩韵  其一','吳頤','宋','宋诗','song-poetry','','[]','攀條弄蕊苧羅人，半軃金翹笑整巾。',64,'全唐诗/poet.song.33000.json','["攀條弄蕊苧羅人，半軃金翹笑整巾。", "慣見冰肌斜映月，似驚酒面暗生春。", "詩翁思苦饒先醉，畫史愁多恐失真。", "寄語東風爲披拂，莫教容易惹芳塵。"]'),
('6121de3b-691a-4c9f-9dca-8afb54c5be7a','次邦憲宣德紅梅詩韵  其二','吳頤','宋','宋诗','song-poetry','','[]','年來惱亂探花人，裂盡陶公漉酒巾。',64,'全唐诗/poet.song.33000.json','["年來惱亂探花人，裂盡陶公漉酒巾。", "傅粉早工欺白雪，施朱更欲媚陽春。", "衣冠未怪多儕俗，花木無情亦喪真。", "他日和羹何所頼，紛紛行見滿前塵。"]'),
('ce3e5da4-5296-44c1-9967-02c16356669d','次邦憲宣德紅梅詩韵  其三','吳頤','宋','宋诗','song-poetry','','[]','玉骨冰肌冷照人，勻紅輕浥絳羅巾。',64,'全唐诗/poet.song.33000.json','["玉骨冰肌冷照人，勻紅輕浥絳羅巾。", "更無凡木能爭艷，定向壺中別得春。", "久稔新詩能寫物，須知樽酒可藏真。", "寄聲閉戶英夫子，體取居塵不染塵。"]'),
('349bf67e-3118-48d0-8dbd-9f925e7fc34b','次邦憲宣德紅梅詩韵  其四','吳頤','宋','宋诗','song-poetry','','[]','留情賦咏盡聞人，似得吳姬爲執巾。',64,'全唐诗/poet.song.33000.json','["留情賦咏盡聞人，似得吳姬爲執巾。", "蝶翅稍應容辨色，桃腮無復敢嬌春。", "似嫌素艷同姑射，著意新粧學太真。", "栽近華堂歌舞地，未容車馬送纖塵。"]'),
('3e8b300c-80b9-4a04-9196-e310ebf89fc9','次邦憲宣德紅梅詩韵  其五','吳頤','宋','宋诗','song-poetry','','[]','絕品花逢絕俗人，吟看屢倒接䍦巾。',64,'全唐诗/poet.song.33000.json','["絕品花逢絕俗人，吟看屢倒接䍦巾。", "剸煩自昔多餘刃，痛飲于今莫負春。", "喜事擅名雖有素，屢空此語恐非真。", "典衣貰酒猶非惡，醉任清歌落暗塵。"]'),
('f752a044-2c7b-48a6-b7cf-60b63fc6f3eb','江村','吳頤','宋','宋诗','song-poetry','','[]','前村笑語近黄昏，獨向江頭望故園。',32,'全唐诗/poet.song.33000.json','["前村笑語近黄昏，獨向江頭望故園。", "漂泊每憐歸去晚，兒童各自解方言。"]'),
('8c45c18d-50e4-49a9-994f-d1085a3998b5','聞寓舍之側花盛開口占絕句  其一','吳頤','宋','宋诗','song-poetry','','[]','冶城西北似村家，每共尋春到日斜。',32,'全唐诗/poet.song.33000.json','["冶城西北似村家，每共尋春到日斜。", "聞說春來花更好，爲憐無伴懶看花。"]'),
('1adac029-e5e1-44eb-9b69-12f0c6790994','聞寓舍之側花盛開口占絕句  其二','吳頤','宋','宋诗','song-poetry','','[]','君嫌無伴懶看花，我向花時更憶家。',32,'全唐诗/poet.song.33000.json','["君嫌無伴懶看花，我向花時更憶家。", "欲趁芙蓉同一醉，秋江好爲送歸槎。"]'),
('e2847c22-7b09-4e47-b9bf-f5f9a36d8961','別後再用前韵寄呈明府','吳頤','宋','宋诗','song-poetry','','[]','所困每患失其親，白首甘爲未遇人。',64,'全唐诗/poet.song.33000.json','["所困每患失其親，白首甘爲未遇人。", "饑目屢常昏皂白，晨炊何敢問新陳。", "强顔愧我猶初仕，策足如君即要津。", "惜別夜闌重款晤，交情終始暖於春。"]'),
('20077f70-0622-4d3d-bd9e-15ffb71b9409','效孟浩然體寄呈邦憲明府','吳頤','宋','宋诗','song-poetry','','[]','繆致棲鸞嘆，頻煩薦鶚書。',48,'全唐诗/poet.song.33000.json','["繆致棲鸞嘆，頻煩薦鶚書。", "未能拋斗米，豈不愛吾廬。", "與世多乖迕，論才信闊疏。", "故人應笑我，早晚遂歸歟。"]'),
('363ca68a-6387-4275-a3dc-b3fa029340e9','明逸宣義披仙館  其一','吳頤','宋','宋诗','song-poetry','','[]','弟兄相踵上青冥，遺跡空餘壓郡城。',64,'全唐诗/poet.song.33000.json','["弟兄相踵上青冥，遺跡空餘壓郡城。", "似惜高風久零落，故開華館面崢嶸。", "樓臺宛轉明朝日，圖史紛披照短檠。", "疑有雙鳬求紫府，檐間時送步虛聲。"]'),
('c0fe8c0b-4245-4f2d-80f0-272778bd0e9a','明逸宣義披仙館  其二','吳頤','宋','宋诗','song-poetry','','[]','仙境清閑識者稀，幾人來此學幽棲。',64,'全唐诗/poet.song.33000.json','["仙境清閑識者稀，幾人來此學幽棲。", "紅泉瑶草春長在，流水桃花路弗迷。", "丹氣猶涵階下井，遺蹤難認壁間題。", "祇憐星石今無恙，夜夜寒光北斗齊。"]'),
('222bef45-ade6-4771-8873-1eb8bf82fabd','出歷坪鋪','吳頤','宋','宋诗','song-poetry','','[]','從來年少怯春寒，老大那堪行路難。',32,'全唐诗/poet.song.33000.json','["從來年少怯春寒，老大那堪行路難。", "已去郵亭重下馬，少須朝日暖征鞍。"]'),
('32c9eed3-dd7d-4a28-b819-2a43a410f185','訪楊湖陰不遇因題其門','陳輔','宋','宋诗','song-poetry','','[]','北山松枌未飄花，白下風輕麥脚斜。',32,'全唐诗/poet.song.33000.json','["北山松枌未飄花，白下風輕麥脚斜。", "身似舊時王謝燕，一年一度到君家。"]'),
('ce6fc3d4-75ae-49fc-a1b8-f94fce6ce5a6','上荆公生辰','陳輔','宋','宋诗','song-poetry','','[]','十月江南已得霜，相君門客小山房。',32,'全唐诗/poet.song.33000.json','["十月江南已得霜，相君門客小山房。", "冬深柏子和香掃，準備生辰作好香。"]'),
('37db904f-6fb2-48ea-84b6-408dd492f38c','題所居','陳輔','宋','宋诗','song-poetry','','[]','湖水山雲繞縣斜，茂林修竹野人家。',32,'全唐诗/poet.song.33000.json','["湖水山雲繞縣斜，茂林修竹野人家。", "宿酲過午無人問，卧聽東風掃落花。"]'),
('7985a661-81b4-471b-ad83-c3e67f55e6ad','梁父吟','陳輔','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','梁父吟，泰山之頂可埋金。',52,'全唐诗/poet.song.33000.json','["梁父吟，泰山之頂可埋金。", "噫嘻蜀道徒崎嶔，南風來舜琴。", "梁父吟，佳人未偶頻傷心。", "四時有恨秋偏深，綠絲空滿簪。"]'),
('ade6e127-b8cb-4b22-a5ee-e6d245184ea1','湖上有作','陳輔','宋','宋诗','song-poetry','','[]','平湖共天遠，浸月坐寒光。',60,'全唐诗/poet.song.33000.json','["平湖共天遠，浸月坐寒光。", "乘流溯荃璧，掉舟尋藥房。", "佳人折輕荷，隨風來珍香。", "顧盼但微笑，眉宇何清揚。", "日暮共携手，遥指煙中湘。"]'),
('5098ae97-fe51-4945-a7f3-6432e5fe3951','題茅山','陳輔','宋','宋诗','song-poetry','','[]','積金峰頂作屏遮，寶閣橫空疊彩霞。',64,'全唐诗/poet.song.33000.json','["積金峰頂作屏遮，寶閣橫空疊彩霞。", "鶴駕往來茅許宅，龍軿交會郭楊家。", "洞天有望人如玉，塵世休觀事若麻。", "我是方臺舊僚友，盍尋歸路種雲芽。"]'),
('474856b7-df2e-48fb-80e9-68c955cf5aee','下泊宮','陳輔','宋','宋诗','song-poetry','','[]','咸陽龍虎此飛昇，二弟東山道亦成。',32,'全唐诗/poet.song.33000.json','["咸陽龍虎此飛昇，二弟東山道亦成。", "不見棠梨司命宅，空餘丹井一泓清。"]'),
('92fb48ac-7235-49bd-aeab-6fb5db672ea7','玉蘭','陳輔','宋','宋诗','song-poetry','','[]','內史北軒多種竹，隠居南洞少栽花。',32,'全唐诗/poet.song.33000.json','["內史北軒多種竹，隠居南洞少栽花。", "藍橋西路青青處，拾得璚兒似虎牙。"]'),
('adee2d40-2226-4a9c-8413-bb60c11a0bcd','送曾公衮赴宣幕','陳輔','宋','宋诗','song-poetry','','[]','當年枳棘藴飛凰，遺愛猶存蔽芾棠。',64,'全唐诗/poet.song.33000.json','["當年枳棘藴飛凰，遺愛猶存蔽芾棠。", "秋水紅蕖新幕府，春風綠草舊池塘。", "芝生瑶圃三重秀，玉出藍田一尺長。", "去去宣城勿留滯，謝家勳業待諸郎。"]'),
('cefff72e-ad0f-467e-85c3-e9eddaa1146d','牛角歌','陳輔','宋','宋诗','song-poetry','','[]','牛角歌，牛角歌，日暮寒雲滿碧陂。',62,'全唐诗/poet.song.33000.json','["牛角歌，牛角歌，日暮寒雲滿碧陂。", "騎牛下山歸曲阿，湖煙濕我蓑。", "牛角歌，牛角歌，浩浩者水魚弗過。", "夷吾向說不我和，嗚呼夷吾奈若何。"]'),
('a0d0c7d6-f437-4ba7-bbf6-7449e92fc83c','悲昔遊','陳輔','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','昔吟梁父思泰山，又歌牛角悲其寒。',175,'全唐诗/poet.song.33000.json','["昔吟梁父思泰山，又歌牛角悲其寒。", "鮑徐英魄今何在，嶺雲關月何漫漫。", "少强眼爲傷時切，老大昏花心易急。", "石巖題墨幾秋風，人世功名杳無跡。", "君不見漢千秋，唐馬周，玄談徒步皆公侯。", "賈生竟止梁王傅，三世郎官虛白頭。", "風雲自古雖傷偶，用舍何嘗繫能否。", "但知信足任平生，計度不如多飲酒。", "願將梁父吟，變作杜宇之聲音。", "願將牛角歌，轉調紫芝絃玉琴。", "五陵石馬散黎軸，惟有箕山青到今。"]'),
('1ac91979-225d-4af3-a9ed-d0d64d025231','登北固山','陳輔','宋','宋诗','song-poetry','','[]','古城龍頂直，孤角雁行稀。',48,'全唐诗/poet.song.33000.json','["古城龍頂直，孤角雁行稀。", "海月天懸鏡，江雲地作衣。", "楚封山或是，秦鑿事還非。", "千古英雄恨，漁人一笑微。"]'),
('621ac042-6046-46b3-9b6a-70a24a653b75','過延陵','陳輔','宋','宋诗','song-poetry','','[]','兩年一劍爲誰留，古邑重來四十秋。',32,'全唐诗/poet.song.33000.json','["兩年一劍爲誰留，古邑重來四十秋。", "不是過辭元亮酒，知公偏愛赤松遊。"]'),
('94433e52-ec6e-4567-bb0b-528b2da936ee','山居  其一','陳輔','宋','宋诗','song-poetry','','[]','山居老樹秋還青，山下漁舟傍晚汀。',32,'全唐诗/poet.song.33000.json','["山居老樹秋還青，山下漁舟傍晚汀。", "一笛月明人不識，自家吹與自家聽。"]'),
('460297f4-de1a-4934-8213-c49d5876c5f6','山居  其二','陳輔','宋','宋诗','song-poetry','','[]','山腰石有千年古，海眼泉無一日乾。',32,'全唐诗/poet.song.33000.json','["山腰石有千年古，海眼泉無一日乾。", "天下蒼生望霖雨，不知龍在此中蟠。"]'),
('a7dde1d3-f126-4a65-ae64-e44320b1fa2c','詩二首  其一','陳輔','宋','宋诗','song-poetry','','[]','牛斗東邊窄，三吳西角深。',24,'全唐诗/poet.song.33000.json','["牛斗東邊窄，三吳西角深。", "山能醒客酒，江會冷人心。"]'),
('1da360b1-9c54-4c22-96e8-06ee36a0d9c8','詩二首  其二','陳輔','宋','宋诗','song-poetry','','[]','山悲秦鑿迷徙浦，柳怨隋奢失故宮。',32,'全唐诗/poet.song.33000.json','["山悲秦鑿迷徙浦，柳怨隋奢失故宮。", "六代興亡明舍火，五州松竹渡甌風。"]'),
('17d1d2da-073a-41bd-9dfd-a8269a325f62','句  其一','陳輔','宋','宋诗','song-poetry','','[]','淥水橋邊駐短篷。',8,'全唐诗/poet.song.33000.json','["淥水橋邊駐短篷。"]'),
