('316695bb-8895-4329-bab9-2e6be465e997','壽昌寺碧溪軒','陳繹','宋','宋诗','song-poetry','','[]','蕭疏華薄隠山村，清淺浮桁带郭門。',32,'全唐诗/poet.song.33000.json','["蕭疏華薄隠山村，清淺浮桁带郭門。", "竹倚欄桿水邊寺，興來題作碧溪軒。"]'),
('71d86684-dbfa-492a-afb7-7aba1dbde9ef','句','陳繹','宋','宋诗','song-poetry','','[]','榕葉堂前生晝陰。',8,'全唐诗/poet.song.33000.json','["榕葉堂前生晝陰。"]'),
('51e2b33c-c83e-4bda-8c27-54e5941bb0c7','題州宅𫇢閣','林積','宋','宋诗','song-poetry','','[]','濟川須用楫，罔水戒行舟。',24,'全唐诗/poet.song.33000.json','["濟川須用楫，罔水戒行舟。", "四海風波路，安眠是勝遊。"]'),
('aded42aa-7a59-4eb7-9ee8-72ad6ec21946','謝鄂倅南宮城','馮京','宋','宋诗','song-poetry','','[]','嘗思鵬海隔飛翻，曾得天風送羽翰。',64,'全唐诗/poet.song.33000.json','["嘗思鵬海隔飛翻，曾得天風送羽翰。", "恩比丘山何以戴，心同金石欲移難。", "經年空嘆音書絕，千里常思道義歡。", "每向江陵訪遺治，邑人猶指縣題看。"]'),
('8d569713-7242-44ac-aaa5-0f70da351222','送程給事知越州','馮京','宋','宋诗','song-poetry','','[]','才毫無地展經綸，白首歸來萬里身。',64,'全唐诗/poet.song.33000.json','["才毫無地展經綸，白首歸來萬里身。", "持節氣凌沙漠使，懷章榮動會稽人。", "平湖翠岫千家月，落日西風一筯蓴。", "南海疲民正回首，滿城歌舞頌年椿。"]'),
('18da806f-c285-4a74-9a06-b24344b4a693','題寺壁','馮京','宋','宋诗','song-poetry','','[]','韓信棲遲項羽窮，手提長劍喝秋風。',32,'全唐诗/poet.song.33000.json','["韓信棲遲項羽窮，手提長劍喝秋風。", "吁嗟天下蒼生眼，不識男兒未濟中。"]'),
('22178d99-194e-4709-8390-52d32a847011','題釣臺','馮京','宋','宋诗','song-poetry','','[]','渭水塵空紺業傾，桐江煙老漢風明。',32,'全唐诗/poet.song.33000.json','["渭水塵空紺業傾，桐江煙老漢風明。", "蚤知賢達窮通意，閒把漁竿只釣名。"]'),
('4ef03b6e-b8bf-486a-bb50-7730411f4254','答伯庸','馮京','宋','宋诗','song-poetry','','[]','孔子之文滿天下，孔子之道滿天下。',32,'全唐诗/poet.song.33000.json','["孔子之文滿天下，孔子之道滿天下。", "得其文者公卿徒，得其道者爲餓夫。"]'),
('f793309f-72c9-42ca-92de-78e7f8a2d422','詔修兩朝國史賜筵史院和首相吳公原韵','馮京','宋','宋诗','song-poetry','','[]','天密叢雲曉，風清一雨餘。',48,'全唐诗/poet.song.33000.json','["天密叢雲曉，風清一雨餘。", "三長太史筆，二典帝皇書。", "按武知何者，霑恩匪幸歟。", "吐茵平日事，何憚污公車。"]'),
('d1a2e26e-801b-4a5a-9cfc-c38acd4af9dc','咏張昌宗','馮京','宋','宋诗','song-poetry','','[]','一水瀠迴繞沌村，子房苗裔此間存。',32,'全唐诗/poet.song.33000.json','["一水瀠迴繞沌村，子房苗裔此間存。", "同居八世三千口，可惜君恩未表門。"]'),
('a038091a-d117-40f5-932a-73935a2d11bc','句  其一','馮京','宋','宋诗','song-poetry','','[]','當時已自傳衣鉢，羞愧猶爲食肉僧。',16,'全唐诗/poet.song.33000.json','["當時已自傳衣鉢，羞愧猶爲食肉僧。"]'),
('fdcbfa3e-6882-422f-8332-6edb77a0084c','句  其二','馮京','宋','宋诗','song-poetry','','[]','吞炭難忘當日事，積薪深愧後來恩。',16,'全唐诗/poet.song.33000.json','["吞炭難忘當日事，積薪深愧後來恩。"]'),
('40031d06-eed1-43b8-8919-bb98b024b3bb','句  其三','馮京','宋','宋诗','song-poetry','','[]','琴彈夜月龍魂冷，劍繫秋風鬼膽粗。',16,'全唐诗/poet.song.33000.json','["琴彈夜月龍魂冷，劍繫秋風鬼膽粗。"]'),
('9127cf5f-a82c-4759-9376-eda3d6899134','句  其四','馮京','宋','宋诗','song-poetry','','[]','吟氣老懷長劍古，醉胸橫得太行寬。',16,'全唐诗/poet.song.33000.json','["吟氣老懷長劍古，醉胸橫得太行寬。"]'),
('4a3502e0-962b-47ee-afa0-f9e1275d5e20','句  其五','馮京','宋','宋诗','song-poetry','','[]','塵埃掉臂離長陌，琴酒和雲入舊山。',16,'全唐诗/poet.song.33000.json','["塵埃掉臂離長陌，琴酒和雲入舊山。"]'),
('e2a7c4c6-b281-4d3d-972f-110e289e783c','句  其六','馮京','宋','宋诗','song-poetry','','[]','豐年足酒容身易，世路無媒著脚難。',16,'全唐诗/poet.song.33000.json','["豐年足酒容身易，世路無媒著脚難。"]'),
('fe99235c-6025-461f-8654-cbef03508990','留題雲門山雍熙院','謝景溫','宋','宋诗','song-poetry','','[]','耶溪欲盡山轉青，中有三寺山爲屏。',256,'全唐诗/poet.song.33000.json','["耶溪欲盡山轉青，中有三寺山爲屏。", "秦峰表裏植蒼翠，仰視萬木相崢嶸。", "雪霜洗盡塵土跡，龍蛇蟄處煙氛生。", "我携賓友事登覽，穿徑已覺毛骨輕。", "窮幽陟險興不盡，巖房留宿神逾清。", "寒隨陰谷一夜來，酒力半酣如不勝。", "狂歌出門步竹逕，正見溪橋雙月明。", "幽泉亂出石竇響，松風遠送哀猿聲。", "凌晨後嶺縱俯仰，長林翠阜何縱橫。", "獻之舊地不可辨，懸崖欲斷石作坑。", "五雲散盡遺迹滅，老僧至今傳此名。", "憑高覽古復太息，翻嗟萬事多廢興。", "丈夫出處固未測，我於山水心難縈。", "區區世路雖可厭，脫身向此誠獨醒。", "豈知乘興事茲樂，賞心不繫窮與亨。", "昔人避世非獲已，我今安學禽鳥情。"]'),
('566507c6-701c-4164-92a9-688ef4225ca1','送程給事知越州','謝景溫','宋','宋诗','song-poetry','','[]','青瑣初辭佩守符，過家衣錦耀鄉閭。',64,'全唐诗/poet.song.33000.json','["青瑣初辭佩守符，過家衣錦耀鄉閭。", "丹心忽厭承明直，白首猶刊麗正書。", "滿目湖山真吏隠，半空樓閣信仙居。", "若耶老叟嗟來暮，應向江頭待隼旟。"]'),
('ddb74b00-0793-4154-8257-80ec0d3f8512','若耶溪','謝景溫','宋','宋诗','song-poetry','','[]','若耶溪出若耶山，浪裏溶溶入醉閑。',64,'全唐诗/poet.song.33000.json','["若耶溪出若耶山，浪裏溶溶入醉閑。", "仙客曾因一箭贈，樵風長到五雲關。", "數峰蘸碧輕清外，雙舸浮春上下間。", "料得當年乘興子，爲貪烟水宿前灣。"]'),
('d9da721b-ef47-4265-a30e-3cba78433f94','金牛驛','吳師孟','宋','宋诗','song-poetry','','[]','唱奇騰怪可刪修，爭奈常情勝謬悠。',64,'全唐诗/poet.song.33000.json','["唱奇騰怪可刪修，爭奈常情勝謬悠。", "禹貢已書開蜀道，秦人安得糞金牛。", "萬重山勢隨坤順，一勺天波到海流。", "自哂據經違世俗，庶幾同志未相尤。"]'),
('ae5739c5-b235-4460-a776-961922d4ff5d','和章質夫成都運司園亭詩 西園','吳師孟','宋','宋诗','song-poetry','','[]','十紀權臣第，修城外臺宅。',48,'全唐诗/poet.song.33000.json','["十紀權臣第，修城外臺宅。", "喬木不知秋，名花數逾百。", "遠如山林幽，近與塵埃隔。", "惠政裕一方，民猶以爲窄。"]'),
('a78fd1c6-fead-440e-86eb-20115f20db83','和章質夫成都運司園亭詩 玉溪堂','吳師孟','宋','宋诗','song-poetry','','[]','華構枕方塘，使臺寂佳致。',48,'全唐诗/poet.song.33000.json','["華構枕方塘，使臺寂佳致。", "二色真楠材，輪奐極精緻。", "花木四面圍，如立復如侍。", "一道仰澄清，此是澄清地。"]'),
('3b3441c2-9248-4cda-94f4-1efe20601e85','和章質夫成都運司園亭詩 雪峰樓','吳師孟','宋','宋诗','song-poetry','','[]','西北有高樓，梁棟雲常起。',48,'全唐诗/poet.song.33000.json','["西北有高樓，梁棟雲常起。", "檐牙挂連蜷，欄影摇清泚。", "爽氣雪山來，一瞬極千里。", "但欲攄遠懷，無憂可銷弭。"]'),
('123c5dff-2ce6-4a27-9893-dbdec834cf5e','和章質夫成都運司園亭詩 海棠軒','吳師孟','宋','宋诗','song-poetry','','[]','花淑對高軒，如用丹青彯。',48,'全唐诗/poet.song.33000.json','["花淑對高軒，如用丹青彯。", "錦水一匳紅，玉臺千面笑。", "松篁兩翠幄，常護東西照。", "子細看韶妍，方知化工妙。"]'),
('eb2cf0ca-011f-4fc0-8152-7582fdcbd414','和章質夫成都運司園亭詩 月臺','吳師孟','宋','宋诗','song-poetry','','[]','雅意待蟾光，煩襟期爽快。',48,'全唐诗/poet.song.33000.json','["雅意待蟾光，煩襟期爽快。", "無雲點太清，遠賢周色界。", "天光浄琉璃，露下真沆瀣。", "勤渠諗後人，宜葺不宜壞。"]'),
('1bd28694-a2f0-4635-9c6d-0c682ecb56a5','和章質夫成都運司園亭詩 翠錦亭','吳師孟','宋','宋诗','song-poetry','','[]','東閣治臺政，西堂備燕飲。',48,'全唐诗/poet.song.33000.json','["東閣治臺政，西堂備燕飲。", "介於二堂間，華構饒花品。", "紅紫鎮長春，四時如活錦。", "公暇一繩床，上有通中枕。"]'),
('6e7bcca7-7708-4e82-950d-5f2195bebb8f','和章質夫成都運司園亭詩 潺玉亭','吳師孟','宋','宋诗','song-poetry','','[]','至人泉石心，俚耳便絲竹。',48,'全唐诗/poet.song.33000.json','["至人泉石心，俚耳便絲竹。", "釃渠逗清泠，朝夕淙寒玉。", "試聽自然聲，不減雲璈曲。", "却返倒聞機，五音常自足。"]'),
('519c00e2-337c-496b-8db9-1b89c63f2c74','和章質夫成都運司園亭詩 茅庵','吳師孟','宋','宋诗','song-poetry','','[]','結茅爲圜屋，環堵不開牖。',48,'全唐诗/poet.song.33000.json','["結茅爲圜屋，環堵不開牖。", "齋居如雁堂，廣長纔六肘。", "深藏子猷竹，不植陶潛柳。", "勿起滅定心，宴坐空諸有。"]'),
('97d4ec07-9749-4d92-9f8f-5001a44406e0','和章質夫成都運司園亭詩 水閣','吳師孟','宋','宋诗','song-poetry','','[]','形制似方橋，島岸相連屬。',48,'全唐诗/poet.song.33000.json','["形制似方橋，島岸相連屬。", "春和逗凉颸，晝影浮浄綠。", "佳人羅襪輕，花時相步續。", "澄瀾忽生暈，下有雙鳬浴。"]'),
('ff445a59-0535-4c68-a5ac-870b2cc88fb7','和章質夫成都運司園亭詩 小亭','吳師孟','宋','宋诗','song-poetry','','[]','尺水走庭除，花木皆周匝。',48,'全唐诗/poet.song.33000.json','["尺水走庭除，花木皆周匝。", "雙亭正相值，僅能容一榻。", "公餘時獨來，隠几聊噓嗒。", "典謁或通名，東榮有賓閤。"]'),
('c691b84e-4c54-46ae-8f5b-bb5524589292','和韓絳遊鴻慶寺','吳師孟','宋','宋诗','song-poetry','','[]','十里東郊道，茲遊歲月深。',96,'全唐诗/poet.song.33000.json','["十里東郊道，茲遊歲月深。", "參僚從行府，高會適叢林。", "穉子喧沽玉，春姬笑子金。", "咳珠僧護寶，醉弁客遺簪。", "天賜連宵澤，民歡畢晝陰。", "分明造物手，自在出塵心。", "非相雖無住，殘芳尚可尋。", "都人望旋旆，車馬又駸駸。"]'),
('c4f2ebaf-f4be-4eac-9e6a-c55fb52b662d','和王公覿賞海雲山茶合江梅花','吳師孟','宋','宋诗','song-poetry','','[]','何處珍叢最早開，海雲山茗合江梅。',64,'全唐诗/poet.song.33000.json','["何處珍叢最早開，海雲山茗合江梅。", "忽傳詩帥邀膚使，不用歌姬侍宴杯。", "曉艷鮮明同綺靡，晚妝清淡奉徘徊。", "此時文酒風流事，豈似臨江放蕩來。"]'),
('f7248d3a-5245-4475-99d9-a207bae14355','瀟湘八景詩 瀟湘夜雨','張經','宋','宋诗','song-poetry','','[]','終夜雨瀟瀟，悶殺孤舟客。',24,'全唐诗/poet.song.33000.json','["終夜雨瀟瀟，悶殺孤舟客。", "滴滴打蓬聲，錯訝靈妃瑟。"]'),
('186614f3-ee88-467b-9703-679e92a8518a','瀟湘八景詩 洞庭夜月','張經','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','秋夜凈無雲，嫦娥展孤鏡。',24,'全唐诗/poet.song.33000.json','["秋夜凈無雲，嫦娥展孤鏡。", "灝氣浸澄波，蕩漾光還定。"]'),
('088161e1-29b7-4dd0-b2ae-5373083122c0','瀟湘八景詩 遠浦歸帆','張經','宋','宋诗','song-poetry','','[]','極浦一帆回，招招近岸開。',24,'全唐诗/poet.song.33000.json','["極浦一帆回，招招近岸開。", "倚船試相問，莫是故鄉來。"]'),
('d44f6783-622c-4fe2-80b7-4d683406e514','瀟湘八景詩 平沙落雁','張經','宋','宋诗','song-poetry','','[]','喚侶下寒汀，爭宿蘆花萼。',24,'全唐诗/poet.song.33000.json','["喚侶下寒汀，爭宿蘆花萼。", "夜半漁翁過，驚起還飛落。"]'),
('6e50c290-8ae0-46c1-a3a1-7ef83bbd6d89','瀟湘八景詩 煙寺晚鐘','張經','宋','宋诗','song-poetry','','[]','野煙寺初暝，僧添寶篆香。',24,'全唐诗/poet.song.33000.json','["野煙寺初暝，僧添寶篆香。", "鯨音送殘照，敲落楚天霜。"]'),
('d2393c99-6b76-48f9-94f7-e11a5d8910a2','瀟湘八景詩 漁村夕照','張經','宋','宋诗','song-poetry','','[]','日落大江頭，返照江村裏。',24,'全唐诗/poet.song.33000.json','["日落大江頭，返照江村裏。", "獨有羨魚翁，垂綸收不起。"]'),
('92198f07-5ae7-4e63-bcef-8ddc9ccc2c57','瀟湘八景詩 山市晴嵐','張經','宋','宋诗','song-poetry','','[]','茅屋開山脚，嵐光映日光。',24,'全唐诗/poet.song.33000.json','["茅屋開山脚，嵐光映日光。", "行人消野興，個個醉壺觴。"]'),
('101a3a03-e68d-4149-a640-b2e13acb4b7e','瀟湘八景詩 江天暮雪','張經','宋','宋诗','song-poetry','','[]','江上雪紛紛，風寒天已暮。',24,'全唐诗/poet.song.33000.json','["江上雪紛紛，風寒天已暮。", "中有泛舟人，興盡迷歸路。"]'),
('dc580fe0-bbde-48a0-8dfd-fdef097991bd','岳陽樓望洞庭','張經','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','每因蜀水漲，橫遏楚江流。',48,'全唐诗/poet.song.33000.json','["每因蜀水漲，橫遏楚江流。", "氣象吞雲夢，波瀾徹夏秋。", "風雲幾開闔，日月自沉浮。", "欲濟誰舟楫，乾坤獨倚樓。"]'),
('ff5440c2-4175-45c1-8741-7be6c8ad8ca1','王質過洞庭','張經','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','雲可有無水，風能奔走沙。',48,'全唐诗/poet.song.33000.json','["雲可有無水，風能奔走沙。", "蟠深鳴老𧌑，飛倦落長鴉。", "地有湘頭尾，山無楚正斜。", "人間與天上，何處礙浮槎。"]'),
('fba9e7cf-53ff-4e37-b0b3-45e448342983','飛來山','安稹','宋','宋诗','song-poetry','','[]','昇山遊罷到賢沙，松檜陰中一境賒。',64,'全唐诗/poet.song.33000.json','["昇山遊罷到賢沙，松檜陰中一境賒。", "自愧簪纓趨仕路，翻憐泉石屬僧家。", "尋窮越國真仙跡，見盡閩封好物華。", "幸接憑熊擁千騎，紅旌歸去照殘霞。"]'),
('3294607d-6d3c-4814-a226-1590143032f7','句','湯夏','宋','宋诗','song-poetry','','[]','浄瓶常带水，破衲任生塵。',12,'全唐诗/poet.song.33000.json','["浄瓶常带水，破衲任生塵。"]'),
('60aa7ce9-7d0d-4631-9636-17dd9b2e8fdf','啟至大寨聞擒鬼章捷書上奏喜而爲詩','王純臣','宋','宋诗','song-poetry','','[]','黄城匹馬捷音來，且喜洮東破虜迴。',32,'全唐诗/poet.song.33000.json','["黄城匹馬捷音來，且喜洮東破虜迴。", "縱使淮西功第一，未聞生縛七渠魁。"]'),
('f54be5b8-6f98-4dde-8f2b-a5cddb097bc7','和王純臣啟至大寨聞擒鬼章捷書上奏喜而爲詩','劉禹卿','宋','宋诗','song-poetry','','[]','英主龍飛嗣位來，洮東首奏捷師回。',32,'全唐诗/poet.song.33000.json','["英主龍飛嗣位來，洮東首奏捷師回。", "若評後聖勳臣序，功占凌烟第一魁。"]'),
('f9d35b14-e8d8-4363-ae1b-eebf74344a6c','行至龍門先寄堯夫先生','李復圭','宋','宋诗','song-poetry','','[]','碧洛青嵩刮眼明，馬頭次第似相迎。',32,'全唐诗/poet.song.33000.json','["碧洛青嵩刮眼明，馬頭次第似相迎。", "天街高士還知否，好約南軒醉一觥。"]'),
('716510d2-9b3d-4e4a-8eb0-ffbbecc8d484','石橋','李復圭','宋','宋诗','song-poetry','','[]','石梁嵲屼據山流，異迹嘗聞記道猷。',64,'全唐诗/poet.song.33000.json','["石梁嵲屼據山流，異迹嘗聞記道猷。", "五百真如誰化滅，三千色界妄探求。", "燈龕焰古長年在，茗盞花濃繼日浮。", "靜境少留塵慮息，松風蕭颯又驚秋。"]'),
('2afb6bb0-be89-4aac-9be3-9f0443c929df','先照亭','李復圭','宋','宋诗','song-poetry','','[]','危梁上下慶雲端，禪剎翬飛插翠巒。',64,'全唐诗/poet.song.33000.json','["危梁上下慶雲端，禪剎翬飛插翠巒。", "華藏貝多緘祕典，香厨莆塞供珍餐。", "回廊跨壑千重峻，懸溜當空六月寒。", "盤礴迥知靈秀境，極高方見地形寬。"]'),
('5ac8ecdf-bad0-4ecb-b7ab-67e32eda4fe1','秀峰上方','李復圭','宋','宋诗','song-poetry','','[]','吳王昔日館娃宮，殿閣鱗差軼碧空。',32,'全唐诗/poet.song.33000.json','["吳王昔日館娃宮，殿閣鱗差軼碧空。", "寂寂香魂招不得，惟餘松柏韵天風。"]');
